const formatMonitorMetricNumber = (value, precision = 2) => {
  if (!Number.isFinite(value)) {
    return 0
  }

  return Number(value.toFixed(precision))
}

const measureTcpLatency = (host, port, timeoutMs = 2000) => {
  return new Promise((resolve) => {
    const startedAt = process.hrtime.bigint()
    const socket = new net.Socket()
    let finished = false

    const finish = (value) => {
      if (finished) {
        return
      }

      finished = true
      socket.destroy()
      resolve(value)
    }

    socket.setTimeout(timeoutMs)
    socket.once('connect', () => {
      const latencyMs = Number(process.hrtime.bigint() - startedAt) / 1_000_000
      finish(formatMonitorMetricNumber(latencyMs))
    })
    socket.once('timeout', () => finish(null))
    socket.once('error', () => finish(null))

    try {
      socket.connect(port, host)
    } catch {
      finish(null)
    }
  })
}

const measureDiskIo = async () => {
  const tempFilePath = path.join(workspaceRoot, 'tmp', `monitoramento-io-${Date.now()}-${Math.random().toString(16).slice(2)}.tmp`)
  const payload = Buffer.alloc(16 * 1024, 'a')

  try {
    const writeStartedAt = process.hrtime.bigint()
    await writeFile(tempFilePath, payload)
    const writeMs = Number(process.hrtime.bigint() - writeStartedAt) / 1_000_000

    const readStartedAt = process.hrtime.bigint()
    await readFile(tempFilePath)
    const readMs = Number(process.hrtime.bigint() - readStartedAt) / 1_000_000

    return {
      writeMs: formatMonitorMetricNumber(writeMs),
      readMs: formatMonitorMetricNumber(readMs),
    }
  } catch {
    return {
      writeMs: 0,
      readMs: 0,
    }
  } finally {
    await unlink(tempFilePath).catch(() => {})
  }
}

const normalizeBatchProcessId = (value) => {
  return String(value ?? '').trim().replace(/[^a-zA-Z0-9:_-]/g, '').slice(0, 120)
}

const normalizeBatchProcessStatus = (value) => {
  const normalizedValue = String(value ?? '').trim().toLowerCase()

  if (normalizedValue === 'running') {
    return 'running'
  }

  if (normalizedValue === 'failed' || normalizedValue === 'error') {
    return 'failed'
  }

  if (normalizedValue === 'completed' || normalizedValue === 'passed' || normalizedValue === 'done') {
    return 'completed'
  }

  return 'running'
}

const calculateBatchProcessEtaSeconds = (startedAt, currentRecord, totalRecords) => {
  if (!startedAt || !Number.isFinite(currentRecord) || !Number.isFinite(totalRecords) || currentRecord <= 0 || totalRecords <= 0 || currentRecord >= totalRecords) {
    return null
  }

  const startedAtDate = new Date(startedAt)

  if (Number.isNaN(startedAtDate.getTime())) {
    return null
  }

  const elapsedMilliseconds = Date.now() - startedAtDate.getTime()

  if (!Number.isFinite(elapsedMilliseconds) || elapsedMilliseconds <= 0) {
    return null
  }

  const progressRatio = currentRecord / totalRecords

  if (!Number.isFinite(progressRatio) || progressRatio <= 0 || progressRatio >= 1) {
    return null
  }

  const estimatedTotalMilliseconds = elapsedMilliseconds / progressRatio
  const remainingMilliseconds = Math.max(0, estimatedTotalMilliseconds - elapsedMilliseconds)

  return Math.ceil(remainingMilliseconds / 1000)
}

const pruneBatchProcessHistory = () => {
  if (batchProcessRuns.size <= batchProcessHistoryLimit) {
    return
  }

  const removableItems = [...batchProcessRuns.values()]
    .filter((item) => item.status !== 'running')
    .sort((left, right) => {
      const leftTimestamp = new Date(left.updatedAt || left.finishedAt || left.startedAt || 0).getTime()
      const rightTimestamp = new Date(right.updatedAt || right.finishedAt || right.startedAt || 0).getTime()
      return leftTimestamp - rightTimestamp
    })

  const removableCount = Math.max(batchProcessRuns.size - batchProcessHistoryLimit, 0)

  for (const removableItem of removableItems.slice(0, removableCount)) {
    batchProcessRuns.delete(removableItem.processId)
  }
}

const upsertBatchProcessRun = (processId, nextValues = {}) => {
  const normalizedProcessId = normalizeBatchProcessId(processId)

  if (!normalizedProcessId) {
    return null
  }

  const currentTimestamp = new Date().toISOString()
  const currentItem = batchProcessRuns.get(normalizedProcessId) ?? {
    processId: normalizedProcessId,
    processType: '',
    processName: '',
    source: '',
    status: 'running',
    isRunning: true,
    startedAt: currentTimestamp,
    finishedAt: '',
    updatedAt: currentTimestamp,
    message: '',
    errorMessage: '',
    currentStepLabel: '',
    currentFileName: '',
    currentRecord: null,
    totalRecords: null,
    progressPercent: null,
    etaSeconds: null,
    requestedFilters: null,
    summary: null,
    metadata: null,
  }

  const mergedStatus = normalizeBatchProcessStatus(nextValues.status ?? currentItem.status)
  const isRunning = mergedStatus === 'running'
  const mergedItem = {
    ...currentItem,
    ...nextValues,
    processId: normalizedProcessId,
    status: mergedStatus,
    isRunning,
    updatedAt: currentTimestamp,
  }

  if (!mergedItem.startedAt) {
    mergedItem.startedAt = currentTimestamp
  }

  if (!isRunning) {
    mergedItem.finishedAt = mergedItem.finishedAt || currentTimestamp
  } else {
    mergedItem.finishedAt = ''
  }

  batchProcessRuns.set(normalizedProcessId, mergedItem)
  pruneBatchProcessHistory()
  return mergedItem
}

const listBatchProcessItems = ({ onlyActive = false } = {}) => {
  const items = [...batchProcessRuns.values()]
    .filter((item) => !onlyActive || item.status === 'running')
    .sort((left, right) => {
      const leftTimestamp = new Date(left.updatedAt || left.finishedAt || left.startedAt || 0).getTime()
      const rightTimestamp = new Date(right.updatedAt || right.finishedAt || right.startedAt || 0).getTime()
      return rightTimestamp - leftTimestamp
    })

  const totals = {
    total: items.length,
    running: items.filter((item) => item.status === 'running').length,
    completed: items.filter((item) => item.status === 'completed').length,
    failed: items.filter((item) => item.status === 'failed').length,
  }

  return {
    generatedAt: new Date().toISOString(),
    ...totals,
    items,
  }
}

const getBatchProcessItem = (processId) => {
  const normalizedProcessId = normalizeBatchProcessId(processId)

  if (!normalizedProcessId) {
    return null
  }

  return batchProcessRuns.get(normalizedProcessId) ?? null
}

const syncApontamentoImportBatchProcess = (importId, statusPayload) => {
  const normalizedImportId = normalizeApontamentoServicosImportId(importId)

  if (!normalizedImportId || !statusPayload) {
    return
  }

  const processId = `apontamento-servicos-import:${normalizedImportId}`
  const totalRecords = Number(statusPayload.totalRecords)
  const currentRecord = Number(statusPayload.currentRecord)
  const progressPercent = Number.isFinite(totalRecords) && totalRecords > 0 && Number.isFinite(currentRecord)
    ? Math.max(0, Math.min(100, Math.round((currentRecord / totalRecords) * 100)))
    : null
  const status = statusPayload.status === 'error'
    ? 'failed'
    : (statusPayload.status === 'completed' ? 'completed' : 'running')
  const message = normalizeRequestValue(statusPayload.message)
    || (status === 'running'
      ? 'Importacao de apontamento em execucao.'
      : (status === 'completed'
        ? 'Importacao de apontamento concluida.'
        : 'Importacao de apontamento finalizada com falhas.'))

  upsertBatchProcessRun(processId, {
    processType: 'apontamento-servicos-import',
    processName: 'Importacao de Apontamento Servicos',
    source: '/api/apontamento-servicos/import-excel',
    status,
    startedAt: normalizeRequestValue(statusPayload.startedAt) || undefined,
    finishedAt: normalizeRequestValue(statusPayload.finishedAt) || undefined,
    message,
    errorMessage: normalizeRequestValue(statusPayload.errorMessage),
    currentStepLabel: 'Processamento de planilha',
    currentFileName: normalizeRequestValue(statusPayload.currentFileName),
    currentRecord: Number.isFinite(currentRecord) ? currentRecord : null,
    totalRecords: Number.isFinite(totalRecords) && totalRecords > 0 ? totalRecords : null,
    progressPercent,
    etaSeconds: status === 'running'
      ? calculateBatchProcessEtaSeconds(
        normalizeRequestValue(statusPayload.startedAt),
        Number.isFinite(currentRecord) ? currentRecord : null,
        Number.isFinite(totalRecords) ? totalRecords : null,
      )
      : null,
    metadata: {
      importId: normalizedImportId,
      processedFiles: Number(statusPayload.processedFiles) || 0,
      processedItems: Number(statusPayload.processedItems) || 0,
      processedDates: Number(statusPayload.processedDates) || 0,
      skippedRecords: Number(statusPayload.skippedRecords) || 0,
      currentFilePath: normalizeRequestValue(statusPayload.currentFilePath),
      oldDirectoryPath: normalizeRequestValue(statusPayload.oldDirectoryPath),
      movedFileName: normalizeRequestValue(statusPayload.movedFileName),
    },
  })
}

const normalizeApontamentoServicosImportId = (value) => {
  return String(value ?? '').trim().replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 80)
}

const getApontamentoServicosImportStatus = (importId) => {
  const normalizedImportId = normalizeApontamentoServicosImportId(importId)

  if (!normalizedImportId) {
    return null
  }

  return apontamentoServicosImportRuns.get(normalizedImportId) ?? null
}

const setApontamentoServicosImportStatus = (importId, nextStatus) => {
  const normalizedImportId = normalizeApontamentoServicosImportId(importId)

  if (!normalizedImportId) {
    return null
  }

  const currentStatus = apontamentoServicosImportRuns.get(normalizedImportId) ?? {
    importId: normalizedImportId,
    status: 'pending',
    directoryPath: '',
    currentFileName: '',
    currentFilePath: '',
    currentFileIndex: 0,
    totalFiles: 0,
    currentRecord: 0,
    totalRecords: 0,
    currentRowNumber: 0,
    processedFiles: 0,
    processedItems: 0,
    processedDates: 0,
    skippedRecords: 0,
    oldDirectoryPath: '',
    movedFileName: '',
    startedAt: new Date().toISOString(),
    finishedAt: '',
    message: '',
    errorMessage: '',
    updatedAt: new Date().toISOString(),
  }

  const mergedStatus = {
    ...currentStatus,
    ...nextStatus,
    importId: normalizedImportId,
    updatedAt: new Date().toISOString(),
  }

  if (!mergedStatus.startedAt) {
    mergedStatus.startedAt = new Date().toISOString()
  }

  if (mergedStatus.status === 'completed' || mergedStatus.status === 'error') {
    mergedStatus.finishedAt = mergedStatus.finishedAt || new Date().toISOString()
  } else {
    mergedStatus.finishedAt = ''
  }

  apontamentoServicosImportRuns.set(normalizedImportId, mergedStatus)
  syncApontamentoImportBatchProcess(normalizedImportId, mergedStatus)
  return mergedStatus
}

const buildApuracaoServicosPostProcessingQueueKey = (key) => {
  if (!key) {
    return ''
  }

  const mesAno = normalizeApuracaoFinanceiraMesAno(key.mesAno)
  const dreCodigo = normalizeRequestValue(key.dreCodigo)
  const ordemServicoCodigo = normalizeRequestValue(key.ordemServicoCodigo)
  const revisao = Number.parseInt(String(key.revisao ?? ''), 10)
  const tipoEscolaCodigo = normalizeRequestValue(key.tipoEscolaCodigo)
  const tipoPessoa = normalizeApuracaoTipoPessoa(key.tipoPessoa)

  if (!mesAno || !dreCodigo || !ordemServicoCodigo || !Number.isInteger(revisao) || revisao < 0 || !tipoEscolaCodigo || !tipoPessoa) {
    return ''
  }

  return [mesAno, dreCodigo, ordemServicoCodigo, revisao, tipoEscolaCodigo, tipoPessoa].join('|')
}

const runApuracaoServicosPostProcessingQueue = async () => {
  if (apuracaoServicosPostProcessingRunning) {
    return
  }

  apuracaoServicosPostProcessingRunning = true

  try {
    while (apuracaoServicosPostProcessingQueue.size > 0) {
      const batchEntries = Array.from(apuracaoServicosPostProcessingQueue.entries()).slice(0, apuracaoServicosPostProcessingBatchSize)

      for (const [queueKey] of batchEntries) {
        apuracaoServicosPostProcessingQueue.delete(queueKey)
      }

      const client = await pool.connect()

      try {
        for (const [, processingKey] of batchEntries) {
          try {
            await syncApuracaoServicosDailyTotals(processingKey, client)
          } catch (error) {
            console.error('[apuracao-servicos-post-processing] Falha ao sincronizar chave', processingKey, error)
          }
        }
      } finally {
        client.release()
      }

      await new Promise((resolve) => setImmediate(resolve))
    }
  } finally {
    apuracaoServicosPostProcessingRunning = false

    if (apuracaoServicosPostProcessingQueue.size > 0) {
      void runApuracaoServicosPostProcessingQueue()
    }
  }
}

const enqueueApuracaoServicosPostProcessing = (keys) => {
  for (const key of Array.isArray(keys) ? keys : []) {
    const queueKey = buildApuracaoServicosPostProcessingQueueKey(key)

    if (!queueKey) {
      continue
    }

    apuracaoServicosPostProcessingQueue.set(queueKey, {
      mesAno: normalizeApuracaoFinanceiraMesAno(key.mesAno),
      dreCodigo: normalizeRequestValue(key.dreCodigo),
      ordemServicoCodigo: normalizeRequestValue(key.ordemServicoCodigo),
      revisao: Number.parseInt(String(key.revisao ?? ''), 10),
      tipoEscolaCodigo: normalizeRequestValue(key.tipoEscolaCodigo),
      tipoPessoa: normalizeApuracaoTipoPessoa(key.tipoPessoa),
    })
  }

  if (!apuracaoServicosPostProcessingRunning && apuracaoServicosPostProcessingQueue.size > 0) {
    void runApuracaoServicosPostProcessingQueue()
  }
}

const resolveXmlImportProgressFilePath = (filePath) => {
  const normalizedValue = String(filePath ?? '').trim()

  if (!normalizedValue) {
    return ''
  }

  const resolvedPath = path.resolve(normalizedValue)
  return resolvedPath.startsWith(workspaceRoot) ? resolvedPath : ''
}

const resetXmlImportProgress = async (progressFilePath) => {
  const resolvedPath = resolveXmlImportProgressFilePath(progressFilePath)

  if (!resolvedPath) {
    return ''
  }

  await mkdir(path.dirname(resolvedPath), { recursive: true })
  await writeFile(resolvedPath, '', 'utf8')

  return resolvedPath
}

const readXmlImportProgress = async (progressFilePath) => {
  const resolvedPath = resolveXmlImportProgressFilePath(progressFilePath)

  if (!resolvedPath) {
    return null
  }

  try {
    const fileContent = await readFile(resolvedPath, 'utf8')
    const lines = String(fileContent ?? '').split(/\r?\n/).map((line) => line.trim()).filter(Boolean)
    const latestLine = lines.at(-1) || ''
    const match = latestLine.match(/registro\s+(\d+)\/(\d+)(?:\s+-\s+(.*))?/i)

    return {
      filePath: resolvedPath,
      line: latestLine,
      current: match ? Number(match[1]) : 0,
      total: match ? Number(match[2]) : 0,
      detail: match ? (match[3] || '') : '',
    }
  } catch {
    return null
  }
}

const appendXmlImportProgress = async (progressFilePath, stepLabel, current, total, detail = '') => {
  const resolvedPath = resolveXmlImportProgressFilePath(progressFilePath)

  if (!resolvedPath) {
    return
  }

  const normalizedStepLabel = String(stepLabel ?? 'Importacao XML').trim() || 'Importacao XML'
  const normalizedDetail = String(detail ?? '').trim()
  const progressLine = `[${new Date().toISOString()}] ${normalizedStepLabel}: registro ${current}/${total}${normalizedDetail ? ` - ${normalizedDetail}` : ''}\n`

  await mkdir(path.dirname(resolvedPath), { recursive: true })
  await appendFile(resolvedPath, progressLine, 'utf8')
}

const truncateCommandOutput = (value, maxLength = 12000) => {
  const normalizedValue = String(value ?? '')

  if (normalizedValue.length <= maxLength) {
    return normalizedValue
  }

  return normalizedValue.slice(-maxLength)
}

const joinCommandOutput = (sections) => truncateCommandOutput(sections
  .filter((section) => String(section?.value ?? '').trim())
  .map((section) => `[${section.title}]\n${String(section.value).trim()}`)
  .join('\n\n'))

const runWorkspaceScript = async ({ scriptName, reportFileName, reportEnvName }) => {
  const reportFilePath = path.join(workspaceRoot, '.artifacts', reportFileName)
  const command = process.platform === 'win32'
    ? (process.env.ComSpec ?? 'cmd.exe')
    : 'npm'
  const commandArgs = process.platform === 'win32'
    ? ['/d', '/s', '/c', `npm run ${scriptName}`]
    : ['run', scriptName]

  const commandResult = await new Promise((resolve, reject) => {
    const child = spawn(command, commandArgs, {
      cwd: workspaceRoot,
      env: {
        ...process.env,
        API_BASE_URL: process.env.API_BASE_URL ?? `http://localhost:${port}`,
        PORT: String(port),
        [reportEnvName]: reportFilePath,
      },
      stdio: ['ignore', 'pipe', 'pipe'],
    })

    let stdout = ''
    let stderr = ''

    child.stdout.on('data', (chunk) => {
      stdout += chunk.toString()
    })

    child.stderr.on('data', (chunk) => {
      stderr += chunk.toString()
    })

    child.on('error', reject)
    child.on('close', (exitCode) => {
      resolve({ stdout, stderr, exitCode: exitCode ?? 1 })
    })
  })

  let reportPayload = null

  try {
    const reportContent = await readFile(reportFilePath, 'utf8')
    reportPayload = JSON.parse(reportContent)
  } catch {
    reportPayload = null
  }

  return {
    scriptName,
    status: commandResult.exitCode === 0 ? 'passed' : 'failed',
    exitCode: commandResult.exitCode,
    reportPath: reportFilePath,
    report: reportPayload,
    stdout: commandResult.stdout,
    stderr: commandResult.stderr,
    stdoutTail: truncateCommandOutput(commandResult.stdout),
    stderrTail: truncateCommandOutput(commandResult.stderr),
  }
}

const runSmokeSuiteCommand = async (suite = 'all') => {
  const normalizedSuite = normalizeRequestValue(suite).toLowerCase() || 'all'

  if (!allowedSmokeSuites.has(normalizedSuite)) {
    throw new Error(`Suite de smoke invalida: ${normalizedSuite}.`)
  }

  const invalidFixtureResult = invalidFixtureSmokeSuites.has(normalizedSuite)
    ? await runWorkspaceScript({
      scriptName: normalizedSuite === 'all' ? 'verify:invalid-fixtures' : `verify:invalid-fixtures:${normalizedSuite}`,
      reportFileName: `invalid-fixture-ui-report-${normalizedSuite}-${Date.now()}-${randomBytes(4).toString('hex')}.json`,
      reportEnvName: 'INVALID_FIXTURE_REPORT_PATH',
    })
    : null

  if (invalidFixtureResult?.exitCode) {
    return {
      suite: normalizedSuite,
      scriptName: invalidFixtureResult.scriptName,
      status: 'failed',
      exitCode: invalidFixtureResult.exitCode,
      reportPath: '',
      report: null,
      stdoutTail: invalidFixtureResult.stdoutTail,
      stderrTail: invalidFixtureResult.stderrTail,
      invalidFixtureStatus: invalidFixtureResult.status,
      invalidFixtureReportPath: invalidFixtureResult.reportPath,
      invalidFixtureReport: invalidFixtureResult.report,
    }
  }

  const smokeResult = await runWorkspaceScript({
    scriptName: normalizedSuite === 'all' ? 'smoke:api' : `smoke:api:${normalizedSuite}`,
    reportFileName: `smoke-ui-report-${normalizedSuite}-${Date.now()}-${randomBytes(4).toString('hex')}.json`,
    reportEnvName: 'SMOKE_REPORT_PATH',
  })

  return {
    suite: normalizedSuite,
    scriptName: smokeResult.scriptName,
    status: smokeResult.status,
    exitCode: smokeResult.exitCode,
    reportPath: smokeResult.reportPath,
    report: smokeResult.report,
    stdoutTail: joinCommandOutput([
      invalidFixtureResult
        ? { title: invalidFixtureResult.scriptName, value: invalidFixtureResult.stdout }
        : null,
      { title: smokeResult.scriptName, value: smokeResult.stdout },
    ]),
    stderrTail: joinCommandOutput([
      invalidFixtureResult
        ? { title: invalidFixtureResult.scriptName, value: invalidFixtureResult.stderr }
        : null,
      { title: smokeResult.scriptName, value: smokeResult.stderr },
    ]),
    invalidFixtureStatus: invalidFixtureResult?.status ?? 'not-run',
    invalidFixtureReportPath: invalidFixtureResult?.reportPath ?? '',
    invalidFixtureReport: invalidFixtureResult?.report ?? null,
  }
}

