const normalizeCpf = (value) => {
  const digits = normalizeRequestValue(value).replace(/\D/g, '').slice(0, 11)

  if (digits.length <= 3) {
    return digits
  }

  if (digits.length <= 6) {
    return `${digits.slice(0, 3)}.${digits.slice(3)}`
  }

  if (digits.length <= 9) {
    return `${digits.slice(0, 3)}.${digits.slice(3, 6)}.${digits.slice(6)}`
  }

  return `${digits.slice(0, 3)}.${digits.slice(3, 6)}.${digits.slice(6, 9)}-${digits.slice(9, 11)}`
}

const isCpfValid = (value) => {
  const digits = value.replace(/\D/g, '')
  return digits.length === 11
}

const normalizeCrmc = (value) => {
  const digits = normalizeRequestValue(value).replace(/\D/g, '').slice(0, 8)

  if (digits.length <= 3) {
    return digits
  }

  if (digits.length <= 6) {
    return `${digits.slice(0, 3)}.${digits.slice(3)}`
  }

  return `${digits.slice(0, 3)}.${digits.slice(3, 6)}-${digits.slice(6, 8)}`
}

const isCrmcValid = (value) => {
  return /^\d{3}\.\d{3}-\d{2}$/.test(value)
}

const normalizeMonitorRg = (value) => {
  return normalizeRequestValue(value)
    .toUpperCase()
    .replace(/[^0-9A-Z.\-/]/g, '')
    .slice(0, 20)
}

const isMonitorRgValid = (value) => {
  return /^[0-9A-Z.\-/]{1,20}$/.test(value)
}

const normalizeTipoVinculo = (value) => {
  const normalizedValue = normalizeRequestValue(value)

  if (!normalizedValue) {
    return ''
  }

  const normalizedKey = normalizedValue
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')

  if (normalizedKey === 'cooperado') {
    return 'Cooperado'
  }

  if (normalizedKey === 'socio') {
    return 'Socio'
  }

  if (normalizedKey === 'funcionario') {
    return 'Funcionario'
  }

  return null
}

const normalizeHistorico = (value) => {
  return normalizeRequestValue(value).slice(0, 200)
}

const normalizeCredenciadaText = (value, maxLength = 255) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .toUpperCase()
    .slice(0, maxLength)
}

const normalizeCepImportLogradouro = (value, maxLength = 255) => {
  const normalizedValue = normalizeCredenciadaText(value, maxLength)

  return normalizedValue.replace(/,\s*\d.*$/, '').trim()
}

const normalizeCredenciadaStatusValue = (value) => {
  const normalizedValue = normalizeCredenciadaText(value, 50)

  if (!normalizedValue) {
    return 'ATIVO'
  }

  return normalizedValue === 'CANCELADO' ? 'CANCELADO' : 'ATIVO'
}

const normalizeCredenciadaTermoPermissao = (value) => {
  const digits = String(value ?? '').replace(/\D/g, '').slice(0, 5)

  if (digits.length <= 4) {
    return digits
  }

  return `${digits.slice(0, 4)}-${digits.slice(4, 5)}`
}

const isCredenciadaTermoPermissaoValid = (value) => /^\d{4}-\d$/.test(String(value ?? '').trim())

const normalizeTpOptanteValue = (value) => normalizeRequestValue(value).toUpperCase().slice(0, 20)

const isTpOptanteValueValid = (value) => ['O', 'N', 'C'].includes(normalizeTpOptanteValue(value))

const normalizeTrocaText = (value, maxLength = 255) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .toUpperCase()
    .slice(0, maxLength)
}

const normalizeTrocaLookupKey = (value) => {
  return normalizeTrocaText(value, 255)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/SUBSTITUI[^A-Z0-9]*FO/g, 'SUBSTITUICAO')
    .replace(/ALTERA[^A-Z0-9]*FO/g, 'ALTERACAO')
    .replace(/ATUALIZA[^A-Z0-9]*AO/g, 'ATUALIZACAO')
    .replace(/REVISA[^A-Z0-9]*AO/g, 'REVISAO')
    .replace(/INCLUSA[^A-Z0-9]*AO/g, 'INCLUSAO')
    .replace(/CORRE[^A-Z0-9]*AO/g, 'CORRECAO')
    .replace(/[^A-Z0-9]/g, '')
}

  const tipoTrocaNaoDefinidoLista = 'NAO DEFINIDO'

const normalizePlacaKey = (value) => {
  return String(value ?? '').toUpperCase().replace(/[^A-Z0-9]/g, '')
}

const normalizeOperationalCode = (value, maxLength = 255) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .toUpperCase()
    .slice(0, maxLength)
}

const normalizeCredenciamentoSituacao = (value) => {
  const normalizedValue = normalizeRequestValue(value)

  if (!normalizedValue) {
    return ''
  }

  const normalizedKey = normalizedValue
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')

  if (normalizedKey === 'ativo') {
    return 'Ativo'
  }

  if (normalizedKey === 'rascunho') {
    return 'Rascunho'
  }

  if (normalizedKey === 'inativo') {
    return 'Inativo'
  }

  if (normalizedKey === 'cancelado') {
    return 'Cancelado'
  }

  if (normalizedKey === 'substituido') {
    return 'Substituido'
  }

  return null
}

const normalizeCredenciamentoAnnotation = (value) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .slice(0, 1000)
}

const normalizeDreOperationalCode = (value) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .toUpperCase()
    .slice(0, 30)
}

const normalizeDreSigla = (value) => {
  return normalizeRequestValue(value)
    .toUpperCase()
    .replace(/[^A-Z]/g, '')
    .slice(0, 2)
}

const normalizeDreDescription = (value) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .toUpperCase()
    .slice(0, 255)
}

const isTegDreText = (value) => {
  return /\bTEG\b/i.test(normalizeImportComparableText(value))
}

const normalizeImportComparableText = (value) => {
  return normalizeRequestValue(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s*([/\\-])\s*/g, '$1')
    .replace(/\s+/g, ' ')
    .toUpperCase()
}

const buildComparableDreSigla = (value) => {
  const normalizedValue = normalizeImportComparableText(value)

  if (!normalizedValue) {
    return ''
  }

  return normalizedValue
    .split(/[^A-Z0-9]+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0])
    .join('')
}

const normalizeEmailList = (value) => {
  const normalizedValue = normalizeRequestValue(value)

  if (!normalizedValue) {
    return ''
  }

  return normalizedValue
    .split(';')
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean)
    .join('; ')
    .slice(0, 255)
}

const isEmailListValid = (value) => {
  if (!value) {
    return true
  }

  return value
    .split(';')
    .map((item) => item.trim())
    .filter(Boolean)
    .every((item) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(item))
}

const normalizeCep = (value) => {
  const digits = normalizeRequestValue(value).replace(/\D/g, '').slice(0, 8)

  if (digits.length <= 5) {
    return digits
  }

  return `${digits.slice(0, 5)}-${digits.slice(5)}`
}

const isCepValid = (value) => {
  return /^\d{5}-\d{3}$/.test(value)
}

const normalizePhoneNumber = (value) => {
  const digits = normalizeRequestValue(value).replace(/\D/g, '').slice(0, 11)

  if (digits.length <= 4) {
    return digits
  }

  if (digits.length <= 8) {
    return `${digits.slice(0, 4)}-${digits.slice(4)}`
  }

  return `${digits.slice(0, 5)}-${digits.slice(5, 9)}`
}

const isPhoneNumberValid = (value) => {
  return /^\d{4,5}-\d{4}$/.test(value)
}

const normalizeCnpjCpf = (value) => {
  const digits = normalizeRequestValue(value).replace(/\D/g, '').slice(0, 14)

  if (digits.length <= 3) {
    return digits
  }

  if (digits.length <= 6) {
    return `${digits.slice(0, 3)}.${digits.slice(3)}`
  }

  if (digits.length <= 9) {
    return `${digits.slice(0, 3)}.${digits.slice(3, 6)}.${digits.slice(6)}`
  }

  if (digits.length <= 11) {
    return `${digits.slice(0, 3)}.${digits.slice(3, 6)}.${digits.slice(6, 9)}-${digits.slice(9, 11)}`
  }

  if (digits.length <= 12) {
    return `${digits.slice(0, 2)}.${digits.slice(2, 5)}.${digits.slice(5, 8)}/${digits.slice(8)}`
  }

  return `${digits.slice(0, 2)}.${digits.slice(2, 5)}.${digits.slice(5, 8)}/${digits.slice(8, 12)}-${digits.slice(12, 14)}`
}

const normalizeTitularDocument = (value) => {
  return normalizeRequestValue(value)
    .replace(/[^0-9.,\/-]/g, '')
    .slice(0, 18)
}

const extractDocumentDigits = (value) => {
  return normalizeRequestValue(value).replace(/\D/g, '')
}

const isCnpjCpfValid = (value) => {
  const digits = value.replace(/\D/g, '')
  return digits.length === 11 || digits.length === 14
}

const findTitularByCnpjCpf = async (cnpjCpf) => {
  const digits = extractDocumentDigits(cnpjCpf)

  if (!digits) {
    return null
  }

  const result = await pool.query(
    `SELECT
       ${titularSelectClause}
     FROM ${titularTableName}
     WHERE regexp_replace(COALESCE(cnpj_cpf, ''), '[^0-9]', '', 'g') = $1
     ORDER BY codigo ASC
     LIMIT 1`,
    [digits],
  )

  return result.rows[0] ?? null
}

const findCredenciadaByCodigo = async (codigo, executor = pool) => {
  const normalizedCodigo = normalizeCondutorCodigo(codigo)

  if (!Number.isInteger(normalizedCodigo) || normalizedCodigo <= 0) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${credenciadaSelectClause}
     FROM credenciada
     WHERE codigo = $1
     ORDER BY codigo ASC
     LIMIT 1`,
    [normalizedCodigo],
  )

  return result.rows[0] ?? null
}

const findCredenciadaByCnpjCpf = async (cnpjCpf, executor = pool) => {
  const digits = extractDocumentDigits(cnpjCpf)

  if (!digits) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${credenciadaSelectClause}
     FROM credenciada
     WHERE regexp_replace(COALESCE(cnpj_cpf, ''), '[^0-9]', '', 'g') = $1
     ORDER BY codigo ASC
     LIMIT 1`,
    [digits],
  )

  return result.rows[0] ?? null
}

const findCredenciadaByName = async (credenciado, executor = pool) => {
  const normalizedCredenciado = normalizeCredenciadaText(credenciado, 255)
  if (!normalizedCredenciado) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${credenciadaSelectClause}
     FROM credenciada
     WHERE UPPER(BTRIM(credenciado)) = $1
     ORDER BY codigo ASC
     LIMIT 1`,
    [normalizedCredenciado],
  )

  return result.rows[0] ?? null
}

const syncCredenciadaTpOptante = async (credenciadaCodigo, tpOptante, executor = pool) => {
  const normalizedCodigo = normalizeCondutorCodigo(credenciadaCodigo)
  const normalizedTpOptante = normalizeTpOptanteValue(tpOptante)

  if (!Number.isInteger(normalizedCodigo) || normalizedCodigo <= 0) {
    return
  }

  await executor.query(
    `UPDATE credenciada
        SET tp_optante = NULLIF($1, ''),
            data_modificacao = NOW()
      WHERE codigo = $2`,
    [normalizedTpOptante, normalizedCodigo],
  )
}

