const isIncludedTipoEscolaForCreche = (item) => {
  const tipoEscolaCodigo = normalizeRequestValue(item?.tipoEscolaCodigo ?? item?.tipo_escola_codigo)

  if (tipoEscolaCodigo === '6') {
    return true
  }

  // Excluir explicitamente os demais grupos citados para o calculo de creche.
  if (tipoEscolaCodigo === '7') {
    return false
  }

  const tipoEscolaSigla = normalizeTipoEscolaLabel(item?.tipoEscolaSigla ?? item?.tipo_escola_sigla)

  if (tipoEscolaSigla === 'CEI') {
    return true
  }

  if (tipoEscolaSigla === 'EMEI' || tipoEscolaSigla === 'EMEF' || tipoEscolaSigla === 'EMEE' || tipoEscolaSigla === 'CCA') {
    return false
  }

  const tipoEscolaDescricao = normalizeTipoEscolaLabel(item?.tipoEscolaDescricao ?? item?.tipo_escola_descricao)

  if (tipoEscolaDescricao.includes('CENTRO DE EDUCACAO INFANTIL')) {
    return true
  }

  if (tipoEscolaDescricao.includes('ESCOLA MUNICIPAL DE EDUCACAO INFANTIL')) {
    return false
  }

  if (tipoEscolaDescricao.includes('ESCOLA MUNICIPAL DE ENSINO FUNDAMENTAL')) {
    return false
  }

  if (tipoEscolaDescricao.includes('ESCOLA MUNICIPAL DE EDUCACAO ESPECIAL')) {
    return false
  }

  if (tipoEscolaDescricao.includes('CENTRO PARA CRIANCAS E ADOLESCENTES')) {
    return false
  }

  return false
}

const getCrecheAccumulatedQuantity = (item) => {
  if (!isIncludedTipoEscolaForCreche(item)) {
    return 0
  }

  const ncPresAcm = Number(item?.naoCadeirantePresencialAcm) || 0
  const atCompNcAcm = Number(item?.atendimentoComplementarNaoCadeiranteAcm) || 0
  return Math.max(0, ncPresAcm + atCompNcAcm)
}

const findLatestRemuneracaoCondicaoValor = async ({ dataReferencia, modalidadeDescricao, tipoBancada, tipoPgtoDescricao, quantidade }, executor = pool) => {
  const result = await executor.query(
    `SELECT mbv.valor::numeric(14,2) AS valor
     FROM modal_bancada_condicao_tipo_pgto_valor mbv
     INNER JOIN modal_bancada_condicao_tipo_pgto assoc ON assoc.codigo = mbv.modal_bancada_condicao_tipo_pgto_codigo
     INNER JOIN modalidade_tipo_bancada mtb ON mtb.codigo = assoc.modalidade_tipo_bancada_codigo
     INNER JOIN modalidade m ON m.codigo = mtb.modalidade_codigo
     INNER JOIN tipo_bancada tb ON tb.codigo = mtb.tipo_bancada_codigo
     INNER JOIN tipo_pgto tp ON tp.codigo = assoc.tipo_pgto_codigo
     INNER JOIN condicao c ON c.codigo = assoc.condicao_codigo
     WHERE ${normalizedSqlTextExpression('m.descricao')} = ${normalizedSqlTextExpression('$1')}
       AND ${normalizedSqlTextExpression('tb.descricao')} = ${normalizedSqlTextExpression('$2')}
       AND ${normalizedSqlTextExpression('tp.descricao')} = ${normalizedSqlTextExpression('$3')}
       AND c.qtde_ini <= $4
       AND c.qtde_fim >= $4
       AND mbv.data <= $5::date
     ORDER BY mbv.data DESC, mbv.codigo DESC
     LIMIT 1`,
    [modalidadeDescricao, tipoBancada, tipoPgtoDescricao, quantidade, dataReferencia],
  )

  if (result.rowCount === 0) {
    throw createHttpError(409, `Nao foi encontrado valor para ${modalidadeDescricao} (${tipoBancada}, ${tipoPgtoDescricao}) com quantidade ${quantidade} na data de operacao.`)
  }

  return Number(result.rows[0].valor) || 0
}

const findLatestRemuneracaoCondicaoValorWithFallback = async ({
  dataReferencia,
  modalidadeDescricaoCandidates,
  tipoBancada,
  tipoPgtoDescricao,
  quantidade,
}, executor = pool) => {
  const normalizedCandidates = [...new Set((Array.isArray(modalidadeDescricaoCandidates) ? modalidadeDescricaoCandidates : [modalidadeDescricaoCandidates])
    .map((candidate) => normalizeRequestValue(candidate))
    .filter(Boolean))]

  if (!normalizedCandidates.length) {
    throw createHttpError(400, 'Modalidade obrigatoria para buscar valor de remuneracao.')
  }

  let notFoundError = null

  for (const modalidadeDescricao of normalizedCandidates) {
    try {
      const valor = await findLatestRemuneracaoCondicaoValor({
        dataReferencia,
        modalidadeDescricao,
        tipoBancada,
        tipoPgtoDescricao,
        quantidade,
      }, executor)

      return {
        modalidadeDescricao,
        valor,
      }
    } catch (error) {
      if (error && typeof error === 'object' && Number((error).statusCode) === 409) {
        notFoundError = error
        continue
      }

      throw error
    }
  }

  if (notFoundError) {
    throw notFoundError
  }

  throw createHttpError(409, `Nao foi encontrado valor para ${normalizedCandidates.join(' ou ')} (${tipoBancada}, ${tipoPgtoDescricao}) com quantidade ${quantidade} na data de operacao.`)
}

const findLatestContinuaValor = async ({ dataReferencia, tipoContinua }, executor = pool) => {
  const normalizedTipoContinua = normalizeRequestValue(tipoContinua)

  if (!normalizedTipoContinua) {
    throw createHttpError(400, 'Tipo de continua obrigatorio para buscar valor de continua.')
  }

  const result = await executor.query(
    `SELECT continua_valor_item.valor::numeric(14,2) AS valor
     FROM continua_valor continua_valor_item
     WHERE ${normalizedSqlTextExpression('continua_valor_item.tipo_continua')} = ${normalizedSqlTextExpression('$1')}
       AND continua_valor_item.data <= $2::date
     ORDER BY continua_valor_item.data DESC, continua_valor_item.codigo DESC
     LIMIT 1`,
    [normalizedTipoContinua, dataReferencia],
  )

  if (result.rowCount === 0) {
    throw createHttpError(409, `Nao foi encontrado valor de continua para ${normalizedTipoContinua} na data de operacao.`)
  }

  return Number(result.rows[0].valor) || 0
}

const findLatestKmValorByQuantidade = async ({ dataReferencia, quantidadeKmAdicional }, executor = pool) => {
  const normalizedQuantidadeKmAdicional = Number(quantidadeKmAdicional)

  if (!Number.isFinite(normalizedQuantidadeKmAdicional) || normalizedQuantidadeKmAdicional <= 0) {
    return null
  }

  const result = await executor.query(
    `SELECT
       km_valor_item.valor::numeric(14,2) AS valor,
       condicao_item.qtde_ini::numeric(14,4) AS qtde_ini
     FROM km_valor km_valor_item
     INNER JOIN condicao condicao_item ON condicao_item.codigo = km_valor_item.condicao_codigo
     WHERE km_valor_item.data <= $1::date
       AND condicao_item.qtde_ini::numeric(14,4) <= $2::numeric(14,4)
     ORDER BY condicao_item.qtde_ini DESC, km_valor_item.data DESC, km_valor_item.codigo DESC
     LIMIT 1`,
    [dataReferencia, normalizedQuantidadeKmAdicional],
  )

  if (result.rowCount === 0) {
    return null
  }

  return {
    valor: Number(result.rows[0].valor) || 0,
    qtdeIni: Number(result.rows[0].qtde_ini) || 0,
  }
}

const findLatestRemuneracaoCondicaoValorByCondicao = async ({ dataReferencia, modalidadeDescricao, tipoBancada, tipoPgtoDescricao, condicaoDescricao }, executor = pool) => {
  const normalizedCondicaoCandidates = [...new Set((Array.isArray(condicaoDescricao) ? condicaoDescricao : [condicaoDescricao])
    .map((candidate) => normalizeRequestValue(candidate))
    .filter(Boolean))]

  if (!normalizedCondicaoCandidates.length) {
    throw createHttpError(400, 'Condicao obrigatoria para buscar valor de remuneracao por condicao.')
  }

  for (const normalizedCondicaoDescricao of normalizedCondicaoCandidates) {
    const result = await executor.query(
      `SELECT mbv.valor::numeric(14,2) AS valor
       FROM modal_bancada_condicao_tipo_pgto_valor mbv
       INNER JOIN modal_bancada_condicao_tipo_pgto assoc ON assoc.codigo = mbv.modal_bancada_condicao_tipo_pgto_codigo
       INNER JOIN modalidade_tipo_bancada mtb ON mtb.codigo = assoc.modalidade_tipo_bancada_codigo
       INNER JOIN modalidade m ON m.codigo = mtb.modalidade_codigo
       INNER JOIN tipo_bancada tb ON tb.codigo = mtb.tipo_bancada_codigo
       INNER JOIN tipo_pgto tp ON tp.codigo = assoc.tipo_pgto_codigo
       INNER JOIN condicao c ON c.codigo = assoc.condicao_codigo
       WHERE ${normalizedSqlTextExpression('m.descricao')} = ${normalizedSqlTextExpression('$1')}
         AND ${normalizedSqlTextExpression('tb.descricao')} = ${normalizedSqlTextExpression('$2')}
         AND ${normalizedSqlTextExpression('tp.descricao')} = ${normalizedSqlTextExpression('$3')}
         AND ${normalizedSqlTextExpression('c.descricao')} = ${normalizedSqlTextExpression('$4')}
         AND mbv.data <= $5::date
       ORDER BY mbv.data DESC, mbv.codigo DESC
       LIMIT 1`,
      [modalidadeDescricao, tipoBancada, tipoPgtoDescricao, normalizedCondicaoDescricao, dataReferencia],
    )

    if (result.rowCount > 0) {
      return Number(result.rows[0].valor) || 0
    }
  }

  throw createHttpError(409, `Nao foi encontrado valor para ${modalidadeDescricao} (${tipoBancada}, ${tipoPgtoDescricao}) nas condicoes ${normalizedCondicaoCandidates.join(' ou ')} na data de operacao.`)
}

const findLatestCcaValorRates = async ({ dataReferencia }, executor = pool) => {
  const convencionalLookup = await findLatestRemuneracaoCondicaoValorWithFallback({
    dataReferencia,
    modalidadeDescricaoCandidates: ['TEG REGULAR'],
    tipoBancada: 'CONVENCIONAL',
    tipoPgtoDescricao: 'PER CAPITA',
    quantidade: 1,
  }, executor)
  const acessivelLookup = await findLatestRemuneracaoCondicaoValorWithFallback({
    dataReferencia,
    modalidadeDescricaoCandidates: ['TEG REGULAR'],
    tipoBancada: 'ACESSIVEL',
    tipoPgtoDescricao: 'PER CAPITA',
    quantidade: 1,
  }, executor)

  return {
    ncUnitMonthlyValor: Number(convencionalLookup.valor) || 0,
    cadUnitMonthlyValor: Number(acessivelLookup.valor) || 0,
  }
}

const calculateCcaValorAmount = ({
  ncQuantidade,
  cadQuantidade,
  ncUnitMonthlyValor,
  cadUnitMonthlyValor,
}) => {
  const normalizedNcQuantidade = Math.max(0, Number(ncQuantidade) || 0)
  const normalizedCadQuantidade = Math.max(0, Number(cadQuantidade) || 0)

  if (normalizedNcQuantidade <= 0 && normalizedCadQuantidade <= 0) {
    return 0
  }

  return normalizeRemuneracaoServicosAmount(
    ((normalizedNcQuantidade * (Number(ncUnitMonthlyValor) || 0)) / 30)
    + ((normalizedCadQuantidade * (Number(cadUnitMonthlyValor) || 0)) / 30),
  )
}

const resolveNormalizedTegModalidadeDailyAmounts = async ({
  quantidade,
  dataReferencia,
  modalidadeDescricaoCandidates,
  tipoBancada,
  quantidadeConfig,
  valorByLookupKey,
}, executor = pool) => {
  const normalizedQuantidade = Math.max(0, Number(quantidade) || 0)

  if (normalizedQuantidade <= 0) {
    return { fixo: 0, percapita: 0 }
  }

  const lookupQuantidade = quantidadeConfig.resolveLookupQuantidade(normalizedQuantidade)
  const modalidadeLookupKey = (Array.isArray(modalidadeDescricaoCandidates) ? modalidadeDescricaoCandidates : [modalidadeDescricaoCandidates]).join('|')
  const fixoLookupKey = `${modalidadeLookupKey}|${tipoBancada}|FIXO|${lookupQuantidade}`
  const percapitaLookupKey = `${modalidadeLookupKey}|${tipoBancada}|PER CAPITA|${lookupQuantidade}`

  let tegFixo = valorByLookupKey.get(fixoLookupKey)
  if (!Number.isFinite(tegFixo)) {
    const fixoLookup = await findLatestRemuneracaoCondicaoValorWithFallback({
      dataReferencia,
      modalidadeDescricaoCandidates,
      tipoBancada,
      tipoPgtoDescricao: 'FIXO',
      quantidade: lookupQuantidade,
    }, executor)
    tegFixo = Number(fixoLookup.valor) || 0
    valorByLookupKey.set(fixoLookupKey, tegFixo)
  }

  let tegPercapita = valorByLookupKey.get(percapitaLookupKey)
  if (!Number.isFinite(tegPercapita)) {
    const percapitaLookup = await findLatestRemuneracaoCondicaoValorWithFallback({
      dataReferencia,
      modalidadeDescricaoCandidates,
      tipoBancada,
      tipoPgtoDescricao: 'PER CAPITA',
      quantidade: lookupQuantidade,
    }, executor)
    tegPercapita = Number(percapitaLookup.valor) || 0
    valorByLookupKey.set(percapitaLookupKey, tegPercapita)
  }

  const percapitaBaseQuantity = normalizedQuantidade
  const percapitaQuantity = percapitaBaseQuantity <= quantidadeConfig.faixa1Limite
    ? percapitaBaseQuantity
    : percapitaBaseQuantity === quantidadeConfig.faixa2Quantidade
      ? percapitaBaseQuantity
      : Math.max(percapitaBaseQuantity - quantidadeConfig.faixa3Inicio + 1, 0)

  return {
    fixo: normalizeRemuneracaoServicosAmount((Number(tegFixo) || 0) / 30),
    percapita: normalizeRemuneracaoServicosAmount(((Number(tegPercapita) || 0) * percapitaQuantity) / 30),
  }
}

const resolveAcessivelTegRegularPercapitaAcrescimoDailyAmount = async ({
  quantidade,
  dataReferencia,
  modalidadeDescricaoCandidates,
  quantidadeConfig,
  valorByLookupKey,
}, executor = pool) => {
  const normalizedQuantidade = Math.max(0, Number(quantidade) || 0)

  if (normalizedQuantidade <= 0) {
    return 0
  }

  const lookupQuantidade = quantidadeConfig.faixa1Limite
  const modalidadeLookupKey = (Array.isArray(modalidadeDescricaoCandidates) ? modalidadeDescricaoCandidates : [modalidadeDescricaoCandidates]).join('|')
  const percapitaLookupKey = `${modalidadeLookupKey}|CONVENCIONAL|PER CAPITA|${lookupQuantidade}|ACESSIVEL_ACRESCIMO_FAIXA15`

  let tegPercapitaUnitario = valorByLookupKey.get(percapitaLookupKey)
  if (!Number.isFinite(tegPercapitaUnitario)) {
    const percapitaLookup = await findLatestRemuneracaoCondicaoValorWithFallback({
      dataReferencia,
      modalidadeDescricaoCandidates,
      tipoBancada: 'CONVENCIONAL',
      tipoPgtoDescricao: 'PER CAPITA',
      quantidade: lookupQuantidade,
    }, executor)
    tegPercapitaUnitario = Number(percapitaLookup.valor) || 0
    valorByLookupKey.set(percapitaLookupKey, tegPercapitaUnitario)
  }

  return normalizeRemuneracaoServicosAmount(((Number(tegPercapitaUnitario) || 0) * normalizedQuantidade) / 30)
}

const listAllApontamentoServicosItems = async ({
  mesAno,
  dreCodigo,
  crmcCondutor,
  placa,
  revisao,
  tipoPessoa,
  dataReferencia,
}, executor = pool) => {
  const pageSize = 1000
  const allItems = []
  let page = 1
  let totalPages = 1

  do {
    const currentPageResult = await listApontamentoServicosItems({
      mesAno,
      dreCodigo,
      crmcCondutor,
      placa,
      revisao,
      tipoPessoa,
      dataReferencia,
      page,
      pageSize,
    }, executor)

    allItems.push(...currentPageResult.items)
    totalPages = currentPageResult.totalPages
    page += 1
  } while (page <= totalPages)

  return allItems
}

const calculateRemuneracaoServicosItems = async ({
  mesAno,
  dreCodigo,
  crmcCondutor,
  placa,
  revisao,
  tipoPessoa,
  dataReferencia,
}, executor = pool) => {
  const allApontamentoItems = await listAllApontamentoServicosItems({
    mesAno,
    dreCodigo,
    crmcCondutor,
    placa,
    revisao,
    tipoPessoa,
    dataReferencia,
  }, executor)

  if (!allApontamentoItems.length) {
    return {
      totalRegistros: 0,
      totalCalculados: 0,
      totalAtualizados: 0,
      totalIgnorados: 0,
    }
  }

  const groupedApontamentoItems = Array.from(allApontamentoItems.reduce((groupedItemsMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentItem = groupedItemsMap.get(groupKey)

    if (!currentItem) {
      groupedItemsMap.set(groupKey, item)
      return groupedItemsMap
    }

    const currentTipoVeiculo = normalizeRequestValue(currentItem.tipoVeiculo)
    const nextTipoVeiculo = normalizeRequestValue(item.tipoVeiculo)

    if (!currentTipoVeiculo && nextTipoVeiculo) {
      groupedItemsMap.set(groupKey, {
        ...currentItem,
        tipoVeiculo: nextTipoVeiculo,
      })

      return groupedItemsMap
    }

    const currentModalidadeDescricao = normalizeRequestValue(currentItem.ordemServicoModalidadeDescricao)
    const nextModalidadeDescricao = normalizeRequestValue(item.ordemServicoModalidadeDescricao)

    if (!currentModalidadeDescricao && nextModalidadeDescricao) {
      groupedItemsMap.set(groupKey, {
        ...currentItem,
        ordemServicoModalidadeDescricao: nextModalidadeDescricao,
      })
    }

    return groupedItemsMap
  }, new Map()).values())

  const normalizedMesAno = normalizeApuracaoFinanceiraMesAno(mesAno)
  const normalizedDate = normalizeApontamentoServicosDate(dataReferencia)
  const compositeKeys = Array.from(new Set(groupedApontamentoItems.map((item) => buildRemuneracaoServicosCompositeKey(item))))
  const remuneracaoResult = await executor.query(
    `SELECT
       mes_ano,
       TO_CHAR(data_referencia, 'YYYY-MM-DD') AS data_referencia,
       CAST(dre_codigo AS text) AS dre_codigo,
       CAST(ordem_servico_codigo AS text) AS ordem_servico_codigo,
       revisao,
       COALESCE(BTRIM(tipo_pessoa), '') AS tipo_pessoa,
       COALESCE(teg_regular_fixo, 0) AS teg_regular_fixo,
       COALESCE(teg_regular_percapita, 0) AS teg_regular_percapita,
       COALESCE(teg_acessivel_fixo, 0) AS teg_acessivel_fixo,
       COALESCE(teg_acessivel_percapita, 0) AS teg_acessivel_percapita,
       COALESCE(teg_especial_regular_fixo, 0) AS teg_especial_regular_fixo,
       COALESCE(teg_especial_regular_percapita, 0) AS teg_especial_regular_percapita,
       COALESCE(teg_especial_acessivel_fixo, 0) AS teg_especial_acessivel_fixo,
       COALESCE(teg_especial_acessivel_percapita, 0) AS teg_especial_acessivel_percapita,
       COALESCE(teg_creche_fixo, 0) AS teg_creche_fixo,
       COALESCE(teg_creche_percapita, 0) AS teg_creche_percapita,
       COALESCE(km_valor, 0) AS km_valor,
       COALESCE(continua_regular, 0) AS continua_regular,
       COALESCE(continua_cadeirante, 0) AS continua_cadeirante,
       COALESCE(cca_valor, 0) AS cca_valor
     FROM remuneracao_servicos
     WHERE mes_ano = $1
       AND data_referencia = $2::date
       AND CONCAT_WS('|', mes_ano, TO_CHAR(data_referencia, 'YYYY-MM-DD'), CAST(dre_codigo AS text), CAST(ordem_servico_codigo AS text), CAST(revisao AS text), COALESCE(BTRIM(tipo_pessoa), '')) = ANY($3::text[])`,
    [normalizedMesAno, normalizedDate, compositeKeys],
  )
  const remuneracaoByKey = new Map(remuneracaoResult.rows.map((row) => [buildRemuneracaoServicosCompositeKey(row), row]))
  const remuneracaoItems = groupedApontamentoItems.map((item) => mapRemuneracaoServicosRow(item, remuneracaoByKey.get(buildRemuneracaoServicosCompositeKey(item))))

  const accumulatedRegularByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getRegularAccumulatedQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedNcPresRegularByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getRegularNcPresAccumulatedQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedAtComplNcRegularByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getRegularAtComplNcAccumulatedQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedAcessivelTegRegularPercapitaNcPresByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getAcessivelTegRegularPercapitaNcPresQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedAcessivelTegRegularPercapitaAtComplNcByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getAcessivelTegRegularPercapitaAtComplNcQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedCrecheTegRegularPercapitaNcPresByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getCrecheTegRegularPercapitaNcPresQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedCrecheTegRegularPercapitaAtComplNcByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getCrecheTegRegularPercapitaAtComplNcQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedEspecialRegularPercapitaAcrescimoByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getEspecialRegularPercapitaAcrescimoQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedAcessivelByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getAcessivelAccumulatedQuantity(item))
    return resultMap
  }, new Map())

  const accumulatedCrecheByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getCrecheAccumulatedQuantity(item))
    return resultMap
  }, new Map())

  const continuaRegularByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + Math.max(0, Number(item.continuaNaoCadeirante) || 0))
    return resultMap
  }, new Map())

  const continuaCadeiranteByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + Math.max(0, Number(item.continuaCadeirante) || 0))
    return resultMap
  }, new Map())

  const kmAdicionalByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    const kilometragem = normalizeApontamentoServicosKm(item.kilometragem)
    const kilometragemValue = Number.isFinite(kilometragem) ? kilometragem : 0
    resultMap.set(groupKey, Number((currentValue + kilometragemValue).toFixed(4)))
    return resultMap
  }, new Map())

  const ccaNcQuantidadeByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getCcaNcPresQuantity(item) + getCcaAtComplNcQuantity(item))
    return resultMap
  }, new Map())

  const ccaCadQuantidadeByGroupKey = allApontamentoItems.reduce((resultMap, item) => {
    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const currentValue = resultMap.get(groupKey) ?? 0
    resultMap.set(groupKey, currentValue + getCcaCadQuantity(item) + getCcaAtComplCadQuantity(item))
    return resultMap
  }, new Map())

  const valorByLookupKey = new Map()
  const itemsToUpsert = []
  let totalCalculados = 0
  let totalAtualizados = 0
  let totalIgnorados = 0

  const modalidadeByTipoBancada = {
    CONVENCIONAL: 'TEG REGULAR',
    ACESSIVEL: 'TEG ACESSIVEL',
    CRECHE: 'TEG CRECHE',
  }

  const quantidadeConfigByTipoBancada = {
    CONVENCIONAL: {
      faixa1Limite: 15,
      faixa2Quantidade: 16,
      faixa3Inicio: 17,
      resolveLookupQuantidade: (quantidade) => quantidade,
    },
    ACESSIVEL: {
      faixa1Limite: 1,
      faixa2Quantidade: 2,
      faixa3Inicio: 3,
      resolveLookupQuantidade: (quantidade) => (quantidade >= 3 ? 3 : quantidade),
    },
    CRECHE: {
      faixa1Limite: 9,
      faixa2Quantidade: 10,
      faixa3Inicio: 11,
      resolveLookupQuantidade: (quantidade) => quantidade,
    },
  }

  const specialRulesByTipoBancada = {
    CONVENCIONAL: {
      fixoCondicaoDescricao: 'Fixo Esp',
      percapitaCondicaoDescricao: 'Per Cap Regular',
      quantityMap: accumulatedRegularByGroupKey,
      outputFixedField: 'tegEspecialRegularFixo',
      outputPercapitaField: 'tegEspecialRegularPercapita',
    },
    ACESSIVEL: {
      fixoCondicaoDescricao: ['Fixo Esp para acessivel', 'Fixo Esp'],
      percapitaCondicaoDescricao: ['Per Cap Acessi', 'Per Cap Acessivel'],
      quantityMap: accumulatedAcessivelByGroupKey,
      outputFixedField: 'tegEspecialAcessivelFixo',
      outputPercapitaField: 'tegEspecialAcessivelPercapita',
    },
  }

  for (const item of remuneracaoItems) {
    const tipoBancada = resolveTipoBancadaFromRemuneracaoItem(item)
    const ordemServicoModalidadeKey = normalizeModalidadeDescriptionKey(item.ordemServicoModalidadeDescricao)
    const isOrdemServicoTegEspecial = ordemServicoModalidadeKey === normalizeModalidadeDescriptionKey('TEG ESPECIAL')
    const isOrdemServicoTegRegular = ordemServicoModalidadeKey === normalizeModalidadeDescriptionKey('TEG REGULAR')
    const modalidadeDescricao = tipoBancada === 'ACESSIVEL' && isOrdemServicoTegRegular
      ? 'TEG REGULAR'
      : modalidadeByTipoBancada[tipoBancada]
    const modalidadeDescricaoCandidates = tipoBancada === 'ACESSIVEL' && isOrdemServicoTegRegular
      ? ['TEG REGULAR']
      : [modalidadeDescricao]

    const groupKey = buildRemuneracaoServicosBaseGroupKey(item)
    const hasContinuaOrKmApontamento = Number(continuaRegularByGroupKey.get(groupKey) ?? 0) > 0
      || Number(continuaCadeiranteByGroupKey.get(groupKey) ?? 0) > 0
      || Number(kmAdicionalByGroupKey.get(groupKey) ?? 0) > 0
    const ccaNcQuantidade = Math.max(0, Number(ccaNcQuantidadeByGroupKey.get(groupKey) ?? 0))
    const ccaCadQuantidade = Math.max(0, Number(ccaCadQuantidadeByGroupKey.get(groupKey) ?? 0))
    const hasCcaApontamento = ccaNcQuantidade > 0 || ccaCadQuantidade > 0

    if (!modalidadeDescricao && !hasContinuaOrKmApontamento && !hasCcaApontamento) {
      totalIgnorados += 1
      continue
    }

    if (!modalidadeDescricao) {
      totalIgnorados += 1
    }

    const quantidade = modalidadeDescricao ? Math.max(0, Number(
      tipoBancada === 'ACESSIVEL'
        ? (accumulatedAcessivelByGroupKey.get(groupKey) ?? 0)
        : tipoBancada === 'CRECHE'
          ? (accumulatedCrecheByGroupKey.get(groupKey) ?? 0)
        : (accumulatedRegularByGroupKey.get(groupKey) ?? 0),
    )) : 0
    const quantidadeConfig = quantidadeConfigByTipoBancada[tipoBancada] ?? quantidadeConfigByTipoBancada.CONVENCIONAL
    const shouldUseSpecialOnlyCalculation = Boolean(modalidadeDescricao)
      && isOrdemServicoTegEspecial
      && Boolean(specialRulesByTipoBancada[tipoBancada])
    let normalizedTegRegularFixo = 0
    let normalizedTegRegularPercapita = 0
    let normalizedTegAcessivelFixo = 0
    let normalizedTegAcessivelPercapita = 0
    let normalizedTegCrecheFixo = 0
    let normalizedTegCrechePercapita = 0

    if (modalidadeDescricao && !shouldUseSpecialOnlyCalculation) {
      if (tipoBancada === 'ACESSIVEL') {
        const acessivelNcPresQuantidade = Math.max(0, Number(accumulatedAcessivelTegRegularPercapitaNcPresByGroupKey.get(groupKey) ?? 0))
        const acessivelAtComplNcQuantidade = Math.max(0, Number(accumulatedAcessivelTegRegularPercapitaAtComplNcByGroupKey.get(groupKey) ?? 0))
        const acessivelRegularModalidadeCandidates = ['TEG REGULAR']
        const convencionalQuantidadeConfig = quantidadeConfigByTipoBancada.CONVENCIONAL

        const ncPresPercapita = await resolveAcessivelTegRegularPercapitaAcrescimoDailyAmount({
          quantidade: acessivelNcPresQuantidade,
          dataReferencia,
          modalidadeDescricaoCandidates: acessivelRegularModalidadeCandidates,
          quantidadeConfig: convencionalQuantidadeConfig,
          valorByLookupKey,
        }, executor)
        const atComplNcPercapita = await resolveAcessivelTegRegularPercapitaAcrescimoDailyAmount({
          quantidade: acessivelAtComplNcQuantidade,
          dataReferencia,
          modalidadeDescricaoCandidates: acessivelRegularModalidadeCandidates,
          quantidadeConfig: convencionalQuantidadeConfig,
          valorByLookupKey,
        }, executor)

        normalizedTegRegularFixo = 0
        normalizedTegRegularPercapita = normalizeRemuneracaoServicosAmount(ncPresPercapita + atComplNcPercapita)

        if (quantidade > 0) {
          const acessivelCadAmounts = await resolveNormalizedTegModalidadeDailyAmounts({
            quantidade,
            dataReferencia,
            modalidadeDescricaoCandidates,
            tipoBancada: 'ACESSIVEL',
            quantidadeConfig: quantidadeConfigByTipoBancada.ACESSIVEL,
            valorByLookupKey,
          }, executor)

          normalizedTegAcessivelFixo = acessivelCadAmounts.fixo
          normalizedTegAcessivelPercapita = acessivelCadAmounts.percapita
        }
      } else if (tipoBancada === 'CRECHE') {
        const crecheNcPresQuantidade = Math.max(0, Number(accumulatedCrecheTegRegularPercapitaNcPresByGroupKey.get(groupKey) ?? 0))
        const crecheAtComplNcQuantidade = Math.max(0, Number(accumulatedCrecheTegRegularPercapitaAtComplNcByGroupKey.get(groupKey) ?? 0))
        const crecheRegularModalidadeCandidates = ['TEG REGULAR']
        const convencionalQuantidadeConfig = quantidadeConfigByTipoBancada.CONVENCIONAL

        const ncPresPercapita = await resolveAcessivelTegRegularPercapitaAcrescimoDailyAmount({
          quantidade: crecheNcPresQuantidade,
          dataReferencia,
          modalidadeDescricaoCandidates: crecheRegularModalidadeCandidates,
          quantidadeConfig: convencionalQuantidadeConfig,
          valorByLookupKey,
        }, executor)
        const atComplNcPercapita = await resolveAcessivelTegRegularPercapitaAcrescimoDailyAmount({
          quantidade: crecheAtComplNcQuantidade,
          dataReferencia,
          modalidadeDescricaoCandidates: crecheRegularModalidadeCandidates,
          quantidadeConfig: convencionalQuantidadeConfig,
          valorByLookupKey,
        }, executor)

        normalizedTegRegularFixo = 0
        normalizedTegRegularPercapita = normalizeRemuneracaoServicosAmount(ncPresPercapita + atComplNcPercapita)

        if (quantidade > 0) {
          const crecheAmounts = await resolveNormalizedTegModalidadeDailyAmounts({
            quantidade,
            dataReferencia,
            modalidadeDescricaoCandidates,
            tipoBancada: 'CRECHE',
            quantidadeConfig,
            valorByLookupKey,
          }, executor)

          normalizedTegCrecheFixo = crecheAmounts.fixo
          normalizedTegCrechePercapita = crecheAmounts.percapita
        }
      } else if (quantidade > 0) {
        const tegModalidadeAmounts = await resolveNormalizedTegModalidadeDailyAmounts({
          quantidade,
          dataReferencia,
          modalidadeDescricaoCandidates,
          tipoBancada,
          quantidadeConfig,
          valorByLookupKey,
        }, executor)

        normalizedTegRegularFixo = tegModalidadeAmounts.fixo
        normalizedTegRegularPercapita = tegModalidadeAmounts.percapita
      }
    }

    const specialRule = specialRulesByTipoBancada[tipoBancada] ?? null
    let normalizedTegEspecialRegularFixo = 0
    let normalizedTegEspecialRegularPercapita = 0
    let normalizedTegEspecialAcessivelFixo = 0
    let normalizedTegEspecialAcessivelPercapita = 0

    if (modalidadeDescricao && isOrdemServicoTegEspecial && specialRule) {
      const specialQuantidade = Math.max(0, Number(specialRule.quantityMap.get(groupKey) ?? 0))

      if (specialQuantidade > 0) {
        const specialFixoConditionKey = Array.isArray(specialRule.fixoCondicaoDescricao)
          ? specialRule.fixoCondicaoDescricao.join('|')
          : String(specialRule.fixoCondicaoDescricao)
        const specialFixoLookupKey = `TEG ESPECIAL|${tipoBancada}|FIXO|${specialFixoConditionKey}`
        let tegEspecialFixo = valorByLookupKey.get(specialFixoLookupKey)

        if (!Number.isFinite(tegEspecialFixo)) {
          tegEspecialFixo = await findLatestRemuneracaoCondicaoValorByCondicao({
            dataReferencia,
            modalidadeDescricao: 'TEG ESPECIAL',
            tipoBancada,
            tipoPgtoDescricao: 'FIXO',
            condicaoDescricao: specialRule.fixoCondicaoDescricao,
          }, executor)
          valorByLookupKey.set(specialFixoLookupKey, tegEspecialFixo)
        }

        const specialPercapitaConditionKey = Array.isArray(specialRule.percapitaCondicaoDescricao)
          ? specialRule.percapitaCondicaoDescricao.join('|')
          : String(specialRule.percapitaCondicaoDescricao)
        const specialPercapitaLookupKey = `TEG ESPECIAL|${tipoBancada}|PER CAPITA|${specialPercapitaConditionKey}`
        let tegEspecialPercapita = valorByLookupKey.get(specialPercapitaLookupKey)

        if (!Number.isFinite(tegEspecialPercapita)) {
          tegEspecialPercapita = await findLatestRemuneracaoCondicaoValorByCondicao({
            dataReferencia,
            modalidadeDescricao: 'TEG ESPECIAL',
            tipoBancada,
            tipoPgtoDescricao: 'PER CAPITA',
            condicaoDescricao: specialRule.percapitaCondicaoDescricao,
          }, executor)
          valorByLookupKey.set(specialPercapitaLookupKey, tegEspecialPercapita)
        }

        const normalizedSpecialFixo = normalizeRemuneracaoServicosAmount((Number(tegEspecialFixo) || 0) / 30)
        const normalizedSpecialPercapita = normalizeRemuneracaoServicosAmount(((Number(tegEspecialPercapita) || 0) * specialQuantidade) / 30)

        if (specialRule.outputFixedField === 'tegEspecialRegularFixo') {
          normalizedTegEspecialRegularFixo = normalizedSpecialFixo
        }

        if (specialRule.outputFixedField === 'tegEspecialAcessivelFixo') {
          normalizedTegEspecialAcessivelFixo = normalizedSpecialFixo
        }

        if (specialRule.outputPercapitaField === 'tegEspecialRegularPercapita') {
          normalizedTegEspecialRegularPercapita = normalizedSpecialPercapita
        }

        if (specialRule.outputPercapitaField === 'tegEspecialAcessivelPercapita') {
          normalizedTegEspecialAcessivelPercapita = normalizedSpecialPercapita
        }
      }
    }

    if (modalidadeDescricao && isOrdemServicoTegEspecial && tipoBancada === 'ACESSIVEL') {
      const especialRegularPercapitaAcrescimoQuantidade = Math.max(0, Number(accumulatedEspecialRegularPercapitaAcrescimoByGroupKey.get(groupKey) ?? 0))

      if (especialRegularPercapitaAcrescimoQuantidade > 0) {
        const especialRegularPercapitaAcrescimoLookupKey = 'TEG ESPECIAL|CONVENCIONAL|PER CAPITA|Per Cap Regular|ACESSIVEL_ACRESCIMO'
        let tegEspecialRegularPercapitaValor = valorByLookupKey.get(especialRegularPercapitaAcrescimoLookupKey)

        if (!Number.isFinite(tegEspecialRegularPercapitaValor)) {
          tegEspecialRegularPercapitaValor = await findLatestRemuneracaoCondicaoValorByCondicao({
            dataReferencia,
            modalidadeDescricao: 'TEG ESPECIAL',
            tipoBancada: 'CONVENCIONAL',
            tipoPgtoDescricao: 'PER CAPITA',
            condicaoDescricao: 'Per Cap Regular',
          }, executor)
          valorByLookupKey.set(especialRegularPercapitaAcrescimoLookupKey, tegEspecialRegularPercapitaValor)
        }

        normalizedTegEspecialRegularPercapita = normalizeRemuneracaoServicosAmount(
          ((Number(tegEspecialRegularPercapitaValor) || 0) * especialRegularPercapitaAcrescimoQuantidade) / 30,
        )
      }
    }

    if (modalidadeDescricao) {
      totalCalculados += 1
    }

    const nextTegRegularFixo = modalidadeDescricao && (tipoBancada === 'CONVENCIONAL' || tipoBancada === 'ACESSIVEL' || tipoBancada === 'CRECHE')
      ? normalizedTegRegularFixo
      : Number(item.tegRegularFixo) || 0
    const nextTegRegularPercapita = modalidadeDescricao && (tipoBancada === 'CONVENCIONAL' || tipoBancada === 'ACESSIVEL' || tipoBancada === 'CRECHE')
      ? normalizedTegRegularPercapita
      : Number(item.tegRegularPercapita) || 0
    const nextTegAcessivelFixo = modalidadeDescricao && tipoBancada === 'ACESSIVEL'
      ? normalizedTegAcessivelFixo
      : Number(item.tegAcessivelFixo) || 0
    const nextTegAcessivelPercapita = modalidadeDescricao && tipoBancada === 'ACESSIVEL'
      ? normalizedTegAcessivelPercapita
      : Number(item.tegAcessivelPercapita) || 0
    const nextTegEspecialRegularFixo = modalidadeDescricao ? normalizedTegEspecialRegularFixo : Number(item.tegEspecialRegularFixo) || 0
    const nextTegEspecialRegularPercapita = modalidadeDescricao ? normalizedTegEspecialRegularPercapita : Number(item.tegEspecialRegularPercapita) || 0
    const nextTegEspecialAcessivelFixo = modalidadeDescricao ? normalizedTegEspecialAcessivelFixo : Number(item.tegEspecialAcessivelFixo) || 0
    const nextTegEspecialAcessivelPercapita = modalidadeDescricao ? normalizedTegEspecialAcessivelPercapita : Number(item.tegEspecialAcessivelPercapita) || 0
    const nextTegCrecheFixo = modalidadeDescricao && tipoBancada === 'CRECHE'
      ? normalizedTegCrecheFixo
      : Number(item.tegCrecheFixo) || 0
    const nextTegCrechePercapita = modalidadeDescricao && tipoBancada === 'CRECHE'
      ? normalizedTegCrechePercapita
      : Number(item.tegCrechePercapita) || 0

    let nextContinuaRegular = 0
    let nextContinuaCadeirante = 0

    const quantidadeContinuaRegular = Math.max(0, Number(continuaRegularByGroupKey.get(groupKey) ?? 0))

    if (quantidadeContinuaRegular > 0) {
      const continuaRegularLookupKey = 'CONTINUA|REGULAR'
      let continuaRegularValor = valorByLookupKey.get(continuaRegularLookupKey)

      if (!Number.isFinite(continuaRegularValor)) {
        continuaRegularValor = await findLatestContinuaValor({
          dataReferencia,
          tipoContinua: 'Regular',
        }, executor)
        valorByLookupKey.set(continuaRegularLookupKey, continuaRegularValor)
      }

      nextContinuaRegular = normalizeRemuneracaoServicosAmount(quantidadeContinuaRegular * (Number(continuaRegularValor) || 0))
    }

    const quantidadeContinuaCadeirante = Math.max(0, Number(continuaCadeiranteByGroupKey.get(groupKey) ?? 0))

    if (quantidadeContinuaCadeirante > 0) {
      const continuaCadeiranteLookupKey = 'CONTINUA|CADEIRANTE'
      let continuaCadeiranteValor = valorByLookupKey.get(continuaCadeiranteLookupKey)

      if (!Number.isFinite(continuaCadeiranteValor)) {
        continuaCadeiranteValor = await findLatestContinuaValor({
          dataReferencia,
          tipoContinua: 'Cadeirante',
        }, executor)
        valorByLookupKey.set(continuaCadeiranteLookupKey, continuaCadeiranteValor)
      }

      nextContinuaCadeirante = normalizeRemuneracaoServicosAmount(quantidadeContinuaCadeirante * (Number(continuaCadeiranteValor) || 0))
    }

    let nextKmValor = 0
    const quantidadeKmAdicional = Math.max(0, Number(kmAdicionalByGroupKey.get(groupKey) ?? 0))

    if (quantidadeKmAdicional > 0) {
      const kmValorLookupKey = `KMVALOR|${quantidadeKmAdicional.toFixed(4)}`
      let kmLookup = valorByLookupKey.get(kmValorLookupKey)

      if (!kmLookup) {
        kmLookup = await findLatestKmValorByQuantidade({
          dataReferencia,
          quantidadeKmAdicional,
        }, executor)
        valorByLookupKey.set(kmValorLookupKey, kmLookup)
      }

      if (kmLookup && quantidadeKmAdicional >= (Number(kmLookup.qtdeIni) || 0)) {
        nextKmValor = normalizeRemuneracaoServicosAmount(quantidadeKmAdicional * (Number(kmLookup.valor) || 0))
      }
    }

    let nextCcaValor = 0

    if (hasCcaApontamento) {
      const ccaValorRatesLookupKey = 'CCA|VALOR_RATES'
      let ccaValorRates = valorByLookupKey.get(ccaValorRatesLookupKey)

      if (!ccaValorRates) {
        ccaValorRates = await findLatestCcaValorRates({
          dataReferencia,
        }, executor)
        valorByLookupKey.set(ccaValorRatesLookupKey, ccaValorRates)
      }

      nextCcaValor = calculateCcaValorAmount({
        ncQuantidade: ccaNcQuantidade,
        cadQuantidade: ccaCadQuantidade,
        ncUnitMonthlyValor: ccaValorRates.ncUnitMonthlyValor,
        cadUnitMonthlyValor: ccaValorRates.cadUnitMonthlyValor,
      })
    }

    const hasAnyValueChange =
      nextTegRegularFixo !== (Number(item.tegRegularFixo) || 0)
      || nextTegRegularPercapita !== (Number(item.tegRegularPercapita) || 0)
      || nextTegAcessivelFixo !== (Number(item.tegAcessivelFixo) || 0)
      || nextTegAcessivelPercapita !== (Number(item.tegAcessivelPercapita) || 0)
      || nextTegEspecialRegularFixo !== (Number(item.tegEspecialRegularFixo) || 0)
      || nextTegEspecialRegularPercapita !== (Number(item.tegEspecialRegularPercapita) || 0)
      || nextTegEspecialAcessivelFixo !== (Number(item.tegEspecialAcessivelFixo) || 0)
      || nextTegEspecialAcessivelPercapita !== (Number(item.tegEspecialAcessivelPercapita) || 0)
      || nextTegCrecheFixo !== (Number(item.tegCrecheFixo) || 0)
      || nextTegCrechePercapita !== (Number(item.tegCrechePercapita) || 0)
      || nextKmValor !== (Number(item.kmValor) || 0)
      || nextContinuaRegular !== (Number(item.continuaRegular) || 0)
      || nextContinuaCadeirante !== (Number(item.continuaCadeirante) || 0)
      || nextCcaValor !== (Number(item.ccaValor) || 0)

    if (hasAnyValueChange) {
      totalAtualizados += 1
    }

    itemsToUpsert.push({
      dreCodigo: item.dreCodigo,
      ordemServicoCodigo: item.ordemServicoCodigo,
      revisao: item.revisao,
      tipoPessoa: item.tipoPessoa,
      tegRegularFixo: nextTegRegularFixo,
      tegRegularPercapita: nextTegRegularPercapita,
      tegAcessivelFixo: nextTegAcessivelFixo,
      tegAcessivelPercapita: nextTegAcessivelPercapita,
      tegEspecialRegularFixo: nextTegEspecialRegularFixo,
      tegEspecialRegularPercapita: nextTegEspecialRegularPercapita,
      tegEspecialAcessivelFixo: nextTegEspecialAcessivelFixo,
      tegEspecialAcessivelPercapita: nextTegEspecialAcessivelPercapita,
      tegCrecheFixo: nextTegCrecheFixo,
      tegCrechePercapita: nextTegCrechePercapita,
      kmValor: nextKmValor,
      continuaRegular: nextContinuaRegular,
      continuaCadeirante: nextContinuaCadeirante,
      ccaValor: nextCcaValor,
    })
  }

  if (itemsToUpsert.length > 0) {
    await upsertRemuneracaoServicosItems({
      mesAno,
      dataReferencia,
      items: itemsToUpsert,
      allowedApuracaoFinanceiraSituacoes: ['A processar', 'Processado'],
      // O recálculo deve atuar apenas na remuneração solicitada.
      // Nao altera status de apuracao nem dados-base do apontamento.
      markApuracaoFinanceiraAsProcessado: false,
    }, executor)
  }

  return {
    totalRegistros: remuneracaoItems.length,
    totalCalculados,
    totalAtualizados,
    totalIgnorados,
  }
}

const upsertRemuneracaoServicosItems = async ({
  mesAno,
  dataReferencia,
  items,
  insertIfMissingOnly = false,
  allowedApuracaoFinanceiraSituacoes = ['Em digitacao'],
  markApuracaoFinanceiraAsProcessado = false,
}, executor = pool) => {
  const normalizedItems = []

  for (const item of items) {
    const dreCodigo = normalizeRequestValue(item.dreCodigo)
    const ordemServicoCodigo = normalizeRequestValue(item.ordemServicoCodigo)
    const tipoPessoa = normalizeApuracaoTipoPessoa(item.tipoPessoa)
    const revisao = Number.parseInt(String(item.revisao ?? ''), 10)
    const metrics = {
      tegRegularFixo: normalizeRemuneracaoServicosAmount(item.tegRegularFixo),
      tegRegularPercapita: normalizeRemuneracaoServicosAmount(item.tegRegularPercapita),
      tegAcessivelFixo: normalizeRemuneracaoServicosAmount(item.tegAcessivelFixo),
      tegAcessivelPercapita: normalizeRemuneracaoServicosAmount(item.tegAcessivelPercapita),
      tegEspecialRegularFixo: normalizeRemuneracaoServicosAmount(item.tegEspecialRegularFixo),
      tegEspecialRegularPercapita: normalizeRemuneracaoServicosAmount(item.tegEspecialRegularPercapita),
      tegEspecialAcessivelFixo: normalizeRemuneracaoServicosAmount(item.tegEspecialAcessivelFixo),
      tegEspecialAcessivelPercapita: normalizeRemuneracaoServicosAmount(item.tegEspecialAcessivelPercapita),
      tegCrecheFixo: normalizeRemuneracaoServicosAmount(item.tegCrecheFixo),
      tegCrechePercapita: normalizeRemuneracaoServicosAmount(item.tegCrechePercapita),
      kmValor: normalizeRemuneracaoServicosAmount(item.kmValor),
      continuaRegular: normalizeRemuneracaoServicosAmount(item.continuaRegular),
      continuaCadeirante: normalizeRemuneracaoServicosAmount(item.continuaCadeirante),
      ccaValor: normalizeRemuneracaoServicosAmount(item.ccaValor),
    }

    if (!dreCodigo || !ordemServicoCodigo || !tipoPessoa || !Number.isInteger(revisao) || revisao < 0) {
      throw createHttpError(400, 'Chave da remuneracao invalida.')
    }

    for (const [label, value] of Object.entries(metrics)) {
      if (!Number.isFinite(value) || value < 0) {
        throw createHttpError(400, `Valor invalido para ${label}.`)
      }
    }

    normalizedItems.push({
      dre_codigo: dreCodigo,
      ordem_servico_codigo: ordemServicoCodigo,
      revisao,
      tipo_pessoa: tipoPessoa,
      teg_regular_fixo: metrics.tegRegularFixo,
      teg_regular_percapita: metrics.tegRegularPercapita,
      teg_acessivel_fixo: metrics.tegAcessivelFixo,
      teg_acessivel_percapita: metrics.tegAcessivelPercapita,
      teg_especial_regular_fixo: metrics.tegEspecialRegularFixo,
      teg_especial_regular_percapita: metrics.tegEspecialRegularPercapita,
      teg_especial_acessivel_fixo: metrics.tegEspecialAcessivelFixo,
      teg_especial_acessivel_percapita: metrics.tegEspecialAcessivelPercapita,
      teg_creche_fixo: metrics.tegCrecheFixo,
      teg_creche_percapita: metrics.tegCrechePercapita,
      km_valor: metrics.kmValor,
      continua_regular: metrics.continuaRegular,
      continua_cadeirante: metrics.continuaCadeirante,
      cca_valor: metrics.ccaValor,
    })
  }

  if (!normalizedItems.length) {
    return
  }

  const editableKeys = [...new Set(normalizedItems.map((item) => `${item.dre_codigo}|${item.revisao}|${item.tipo_pessoa}`))]

  for (const editableKey of editableKeys) {
    const [dreCodigo, revisaoText, tipoPessoa] = editableKey.split('|')

    await ensureApuracaoServicosEditable({
      mesAno,
      dreCodigo,
      revisao: Number.parseInt(revisaoText, 10),
      tipoPessoa,
      createIfMissing: false,
      allowedSituacoes: allowedApuracaoFinanceiraSituacoes,
    }, executor)
  }

  const payloadJson = JSON.stringify(normalizedItems)
  const parentMissingResult = await executor.query(
    `WITH input_rows AS (
       SELECT *
       FROM jsonb_to_recordset($1::jsonb) AS input_item (
         dre_codigo text,
         ordem_servico_codigo text,
         revisao integer,
         tipo_pessoa text,
         teg_regular_fixo numeric,
         teg_regular_percapita numeric,
         teg_acessivel_fixo numeric,
         teg_acessivel_percapita numeric,
         teg_especial_regular_fixo numeric,
         teg_especial_regular_percapita numeric,
         teg_especial_acessivel_fixo numeric,
         teg_especial_acessivel_percapita numeric,
         teg_creche_fixo numeric,
         teg_creche_percapita numeric,
         km_valor numeric,
         continua_regular numeric,
         continua_cadeirante numeric,
         cca_valor numeric
       )
     )
     SELECT 1
     FROM input_rows
     LEFT JOIN apuracao_servicos aps
       ON aps.mes_ano = $2
      AND aps.data_referencia = $3::date
      AND CAST(aps.dre_codigo AS text) = input_rows.dre_codigo
      AND CAST(aps.ordem_servico_codigo AS text) = input_rows.ordem_servico_codigo
      AND aps.revisao = input_rows.revisao
      AND COALESCE(BTRIM(aps.tipo_pessoa), '') = input_rows.tipo_pessoa
     WHERE aps.ordem_servico_codigo IS NULL
     LIMIT 1`,
    [payloadJson, mesAno, dataReferencia],
  )

  if (parentMissingResult.rowCount > 0) {
    throw createHttpError(409, 'Apontamento/total de servicos nao encontrado para a chave informada na data de referencia.')
  }

  await executor.query(
    `WITH input_rows AS (
       SELECT *
       FROM jsonb_to_recordset($1::jsonb) AS input_item (
         dre_codigo text,
         ordem_servico_codigo text,
         revisao integer,
         tipo_pessoa text,
         teg_regular_fixo numeric,
         teg_regular_percapita numeric,
         teg_acessivel_fixo numeric,
         teg_acessivel_percapita numeric,
         teg_especial_regular_fixo numeric,
         teg_especial_regular_percapita numeric,
         teg_especial_acessivel_fixo numeric,
         teg_especial_acessivel_percapita numeric,
         teg_creche_fixo numeric,
         teg_creche_percapita numeric,
         km_valor numeric,
         continua_regular numeric,
         continua_cadeirante numeric,
         cca_valor numeric
       )
     )
     INSERT INTO remuneracao_servicos (
       mes_ano,
       data_referencia,
       dre_codigo,
       ordem_servico_codigo,
       revisao,
       tipo_pessoa,
       teg_regular_fixo,
       teg_regular_percapita,
       teg_acessivel_fixo,
       teg_acessivel_percapita,
       teg_especial_regular_fixo,
       teg_especial_regular_percapita,
       teg_especial_acessivel_fixo,
       teg_especial_acessivel_percapita,
       teg_creche_fixo,
       teg_creche_percapita,
       km_valor,
       continua_regular,
       continua_cadeirante,
       cca_valor,
       data_alteracao
     )
     SELECT
       $2,
       $3::date,
       input_rows.dre_codigo::int,
       input_rows.ordem_servico_codigo::int,
       input_rows.revisao,
       input_rows.tipo_pessoa,
       input_rows.teg_regular_fixo,
       input_rows.teg_regular_percapita,
       input_rows.teg_acessivel_fixo,
       input_rows.teg_acessivel_percapita,
       input_rows.teg_especial_regular_fixo,
       input_rows.teg_especial_regular_percapita,
       input_rows.teg_especial_acessivel_fixo,
       input_rows.teg_especial_acessivel_percapita,
       input_rows.teg_creche_fixo,
       input_rows.teg_creche_percapita,
       input_rows.km_valor,
       input_rows.continua_regular,
       input_rows.continua_cadeirante,
       input_rows.cca_valor,
       NOW()
     FROM input_rows
     ON CONFLICT (mes_ano, data_referencia, dre_codigo, ordem_servico_codigo, revisao, tipo_pessoa)
     ${insertIfMissingOnly
    ? 'DO NOTHING'
    : `DO UPDATE SET
         teg_regular_fixo = EXCLUDED.teg_regular_fixo,
         teg_regular_percapita = EXCLUDED.teg_regular_percapita,
         teg_acessivel_fixo = EXCLUDED.teg_acessivel_fixo,
         teg_acessivel_percapita = EXCLUDED.teg_acessivel_percapita,
         teg_especial_regular_fixo = EXCLUDED.teg_especial_regular_fixo,
         teg_especial_regular_percapita = EXCLUDED.teg_especial_regular_percapita,
         teg_especial_acessivel_fixo = EXCLUDED.teg_especial_acessivel_fixo,
         teg_especial_acessivel_percapita = EXCLUDED.teg_especial_acessivel_percapita,
         teg_creche_fixo = EXCLUDED.teg_creche_fixo,
         teg_creche_percapita = EXCLUDED.teg_creche_percapita,
         km_valor = EXCLUDED.km_valor,
         continua_regular = EXCLUDED.continua_regular,
         continua_cadeirante = EXCLUDED.continua_cadeirante,
         cca_valor = EXCLUDED.cca_valor,
         data_alteracao = NOW()`}`,
    [payloadJson, mesAno, dataReferencia],
  )

  if (markApuracaoFinanceiraAsProcessado) {
    for (const editableKey of editableKeys) {
      const [dreCodigo, revisaoText, tipoPessoa] = editableKey.split('|')

      await executor.query(
        `UPDATE apuracao_financeira
         SET situacao = 'Processado',
             data_alteracao = NOW()
         WHERE mes_ano = $1
           AND CAST(dre_codigo AS text) = $2
           AND revisao = $3
           AND BTRIM(tipo_pessoa) = $4
           AND BTRIM(situacao) = 'A processar'`,
        [mesAno, dreCodigo, Number.parseInt(revisaoText, 10), tipoPessoa],
      )
    }
  }
}

const syncApuracaoServicosDailyTotals = async (key, executor = pool) => {
  await executor.query(
    `WITH accumulated AS (
       SELECT
         aps.mes_ano,
         aps.data_referencia,
         aps.dre_codigo,
         aps.ordem_servico_codigo,
         aps.revisao,
         aps.tipo_escola_codigo,
         COALESCE(BTRIM(aps.tipo_pessoa), '') AS tipo_pessoa,
         COALESCE(SUM(aps.nc_pres) OVER service_window, 0)::integer AS nc_pres_acm,
         COALESCE(SUM(aps.cad) OVER service_window, 0)::integer AS cad_acm,
         COALESCE(SUM(aps.ac_nc) OVER service_window, 0)::integer AS ac_nc_acm,
         COALESCE(SUM(aps.ac_cad) OVER service_window, 0)::integer AS ac_cad_acm,
         COALESCE(SUM(aps.cont_nc) OVER service_window, 0)::integer AS cont_nc_acm,
         COALESCE(SUM(aps.cont_cad) OVER service_window, 0)::integer AS cont_cad_acm
       FROM apuracao_servicos aps
       WHERE aps.mes_ano = $1
         AND aps.dre_codigo = $2
         AND aps.ordem_servico_codigo = $3
         AND aps.revisao = $4
         AND aps.tipo_escola_codigo = $5
         AND COALESCE(BTRIM(aps.tipo_pessoa), '') = $6
       WINDOW service_window AS (
         PARTITION BY aps.mes_ano, aps.dre_codigo, aps.ordem_servico_codigo, aps.revisao, aps.tipo_escola_codigo, COALESCE(BTRIM(aps.tipo_pessoa), '')
         ORDER BY aps.data_referencia ASC
         ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
       )
     )
     UPDATE apuracao_servicos aps
     SET nc_pres_acm = accumulated.nc_pres_acm,
         cad_acm = accumulated.cad_acm,
         ac_nc_acm = accumulated.ac_nc_acm,
         ac_cad_acm = accumulated.ac_cad_acm,
         cont_nc_acm = accumulated.cont_nc_acm,
         cont_cad_acm = accumulated.cont_cad_acm
     FROM accumulated
     WHERE aps.mes_ano = accumulated.mes_ano
       AND aps.data_referencia = accumulated.data_referencia
       AND aps.dre_codigo = accumulated.dre_codigo
       AND aps.ordem_servico_codigo = accumulated.ordem_servico_codigo
       AND aps.revisao = accumulated.revisao
       AND aps.tipo_escola_codigo = accumulated.tipo_escola_codigo
       AND COALESCE(BTRIM(aps.tipo_pessoa), '') = accumulated.tipo_pessoa`,
    [key.mesAno, Number.parseInt(key.dreCodigo, 10), Number.parseInt(key.ordemServicoCodigo, 10), key.revisao, Number.parseInt(key.tipoEscolaCodigo, 10), key.tipoPessoa],
  )

  await syncApuracaoServicosMaterializedFields(key, executor)
}

const modalidadeTipoBancadaAssociationSelectClause = `
  CAST(associacao.codigo AS text) AS codigo,
  CAST(associacao.modalidade_codigo AS text) AS modalidade_codigo,
  BTRIM(CAST(modalidade_item.descricao AS text)) AS modalidade_descricao,
  CAST(associacao.tipo_bancada_codigo AS text) AS tipo_bancada_codigo,
  BTRIM(CAST(tipo_bancada_item.descricao AS text)) AS tipo_bancada_descricao`

const modalBancadaTpPagtoCondicaoSelectClause = `
  CAST(relacao.codigo AS text) AS codigo,
  CAST(relacao.modalidade_tipo_bancada_codigo AS text) AS modalidade_tipo_bancada_codigo,
  CAST(modalidade_item.codigo AS text) AS modalidade_codigo,
  BTRIM(CAST(modalidade_item.descricao AS text)) AS modalidade_descricao,
  CAST(tipo_bancada_item.codigo AS text) AS tipo_bancada_codigo,
  BTRIM(CAST(tipo_bancada_item.descricao AS text)) AS tipo_bancada_descricao,
  CAST(tipo_pgto_item.codigo AS text) AS tipo_pgto_codigo,
  BTRIM(CAST(tipo_pgto_item.descricao AS text)) AS tipo_pgto_descricao,
  CAST(condicao_item.codigo AS text) AS condicao_codigo,
  BTRIM(CAST(condicao_item.descricao AS text)) AS condicao_descricao,
  condicao_item.qtde_ini AS condicao_qtde_ini,
  condicao_item.qtde_fim AS condicao_qtde_fim`

const findModalidadeTipoBancadaAssociationByCodigo = async (codigo, executor = pool) => {
  const normalizedCodigo = normalizeRequestValue(codigo)

  if (!normalizedCodigo) {
    return null
  }

  const result = await executor.query(
    `SELECT ${modalidadeTipoBancadaAssociationSelectClause}
     FROM modalidade_tipo_bancada associacao
     INNER JOIN modalidade modalidade_item ON modalidade_item.codigo = associacao.modalidade_codigo
     INNER JOIN tipo_bancada tipo_bancada_item ON tipo_bancada_item.codigo = associacao.tipo_bancada_codigo
     WHERE CAST(associacao.codigo AS text) = $1
     LIMIT 1`,
    [normalizedCodigo],
  )

  return result.rows[0] ?? null
}

const findModalBancadaTpPagtoCondicaoByCodigo = async (codigo, executor = pool) => {
  const normalizedCodigo = normalizeRequestValue(codigo)

  if (!normalizedCodigo) {
    return null
  }

  const result = await executor.query(
    `SELECT ${modalBancadaTpPagtoCondicaoSelectClause}
    FROM modal_bancada_condicao_tipo_pgto relacao
     INNER JOIN modalidade_tipo_bancada associacao ON associacao.codigo = relacao.modalidade_tipo_bancada_codigo
     INNER JOIN modalidade modalidade_item ON modalidade_item.codigo = associacao.modalidade_codigo
     INNER JOIN tipo_bancada tipo_bancada_item ON tipo_bancada_item.codigo = associacao.tipo_bancada_codigo
     INNER JOIN tipo_pgto tipo_pgto_item ON tipo_pgto_item.codigo = relacao.tipo_pgto_codigo
     INNER JOIN condicao condicao_item ON condicao_item.codigo = relacao.condicao_codigo
     WHERE CAST(relacao.codigo AS text) = $1
     LIMIT 1`,
    [normalizedCodigo],
  )

  return result.rows[0] ?? null
}

const modalBancadaTpPagtoCondicaoValorSelectClause = `
  CAST(valor_relacao.codigo AS text) AS codigo,
  CAST(valor_relacao.modal_bancada_condicao_tipo_pgto_codigo AS text) AS modal_bancada_condicao_tipo_pgto_codigo,
  TO_CHAR(valor_relacao.data, 'YYYY-MM-DD') AS data,
  COALESCE(TO_CHAR(valor_relacao.valor, 'FM999999999990.00'), '0.00') AS valor,
  CAST(relacao.codigo AS text) AS relacao_codigo,
  CAST(relacao.modalidade_tipo_bancada_codigo AS text) AS modalidade_tipo_bancada_codigo,
  CAST(modalidade_item.codigo AS text) AS modalidade_codigo,
  BTRIM(CAST(modalidade_item.descricao AS text)) AS modalidade_descricao,
  CAST(tipo_bancada_item.codigo AS text) AS tipo_bancada_codigo,
  BTRIM(CAST(tipo_bancada_item.descricao AS text)) AS tipo_bancada_descricao,
  CAST(tipo_pgto_item.codigo AS text) AS tipo_pgto_codigo,
  BTRIM(CAST(tipo_pgto_item.descricao AS text)) AS tipo_pgto_descricao,
  CAST(condicao_item.codigo AS text) AS condicao_codigo,
  BTRIM(CAST(condicao_item.descricao AS text)) AS condicao_descricao`

const kmValorSelectClause = `
  CAST(km_valor_item.codigo AS text) AS codigo,
  CAST(km_valor_item.condicao_codigo AS text) AS condicao_codigo,
  BTRIM(CAST(condicao_item.descricao AS text)) AS condicao_descricao,
  condicao_item.qtde_ini AS condicao_qtde_ini,
  condicao_item.qtde_fim AS condicao_qtde_fim,
  TO_CHAR(km_valor_item.data, 'YYYY-MM-DD') AS data,
  COALESCE(TO_CHAR(km_valor_item.valor, 'FM999999999990.00'), '0.00') AS valor`

const parametroVeiculoSelectClause = `
  CAST(parametro_veiculo_item.codigo AS text) AS codigo,
  CAST(parametro_veiculo_item.modalidade_tipo_bancada_codigo AS text) AS modalidade_tipo_bancada_codigo,
  CAST(modalidade_item.codigo AS text) AS modalidade_codigo,
  BTRIM(CAST(modalidade_item.descricao AS text)) AS modalidade_descricao,
  CAST(tipo_bancada_item.codigo AS text) AS tipo_bancada_codigo,
  BTRIM(CAST(tipo_bancada_item.descricao AS text)) AS tipo_bancada_descricao,
  BTRIM(CAST(parametro_veiculo_item.condicao AS text)) AS condicao,
  parametro_veiculo_item.qtde_condicao AS qtde_condicao,
  TO_CHAR(parametro_veiculo_item.data, 'YYYY-MM-DD') AS data`

const continuaValorSelectClause = `
  CAST(continua_valor_item.codigo AS text) AS codigo,
  BTRIM(CAST(continua_valor_item.tipo_continua AS text)) AS tipo_continua,
  TO_CHAR(continua_valor_item.data, 'YYYY-MM-DD') AS data,
  COALESCE(TO_CHAR(continua_valor_item.valor, 'FM999999999990.00'), '0.00') AS valor`

