const recalculateSpecialVehicleValues = async (executor = pool, options = {}) => {
  const conventionalRows = await recalculateSpecialConventionalVehicleValues(executor, options)
  const accessibleRows = await recalculateSpecialAccessibleVehicleValues(executor, options)
  const regularConventionalRows = await recalculateRegularConventionalVehicleValues(executor, options)
  const regularAccessibleRows = await recalculateRegularAccessibleVehicleValues(executor, options)
  const regularCrecheRows = await recalculateRegularCrecheVehicleValues(executor, options)

  return [...conventionalRows, ...accessibleRows, ...regularConventionalRows, ...regularAccessibleRows, ...regularCrecheRows]
}

const fetchVeiculoAuditItemByCrm = async (executor, crm) => {
  const normalizedCrm = normalizeVehicleCrm(crm)

  if (!normalizedCrm) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${veiculoAuditSelectClause}
     FROM veiculo
     WHERE UPPER(BTRIM(COALESCE(crm, ''))) = UPPER($1)
     ORDER BY codigo ASC
     LIMIT 1`,
    [normalizedCrm],
  )

  return result.rows[0] ?? null
}

const fetchVeiculoAuditItemByPlaca = async (executor, placa) => {
  const normalizedPlaca = normalizeVehiclePlaca(placa)

  if (!normalizedPlaca) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${veiculoAuditSelectClause}
     FROM veiculo
     WHERE regexp_replace(UPPER(COALESCE(placas, '')), '[^A-Z0-9]', '', 'g') = $1
     ORDER BY codigo ASC
     LIMIT 1`,
    [normalizedPlaca],
  )

  return result.rows[0] ?? null
}

const normalizeAuditActor = (value) => {
  return normalizeRequestValue(value)
    .replace(/\s+/g, ' ')
    .slice(0, 255)
}

const resolveRequestActor = (request, fallbackValue = 'SISTEMA') => {
  const headerActor = normalizeAuditActor(
    request.headers['x-user-name']
      ?? request.headers['x-user-email']
      ?? request.headers['x-auth-user']
      ?? '',
  )

  return headerActor || normalizeAuditActor(fallbackValue) || 'SISTEMA'
}

const findTrocaByCodigoOrDescricao = async ({ codigo, descricao }) => {
  const normalizedCodigo = normalizeRequestValue(codigo)
  const normalizedDescricao = normalizeTrocaText(descricao, 255)
  const normalizedDescricaoKey = normalizeTrocaLookupKey(descricao)

  if (!normalizedCodigo && !normalizedDescricaoKey) {
    return null
  }

  if (normalizedCodigo) {
    const result = await pool.query(
      `SELECT ${trocaSelectClause}
       FROM tipo_troca
       WHERE CAST(codigo AS text) = $1
       ORDER BY codigo ASC
       LIMIT 1`,
      [normalizedCodigo],
    )

    if (result.rows[0]) {
      return result.rows[0]
    }
  }

  if (!normalizedDescricaoKey) {
    return null
  }

  const result = await pool.query(
    `SELECT ${trocaSelectClause}
     FROM tipo_troca
     ORDER BY codigo ASC`,
  )

  return result.rows.find((item) => normalizeTrocaLookupKey(item.lista) === normalizedDescricaoKey) ?? null
}

const ensureDefaultTrocaNaoDefinido = async (executor = pool) => {
  const queryExecutor = executor && typeof executor.query === 'function' ? executor : pool
  const existingItem = await findTrocaByCodigoOrDescricao({ descricao: tipoTrocaNaoDefinidoLista })

  if (existingItem) {
    return existingItem
  }

  await queryExecutor.query(
    `INSERT INTO tipo_troca (
       controle,
       lista,
       data_inclusao,
       data_modificacao
     )
     SELECT
       COALESCE(MAX(controle), 0) + 1,
       $1,
       NOW(),
       NOW()
     FROM tipo_troca
     ON CONFLICT (lista) DO UPDATE
     SET data_modificacao = NOW()`,
    [tipoTrocaNaoDefinidoLista],
  )

  return findTrocaByCodigoOrDescricao({ descricao: tipoTrocaNaoDefinidoLista })
}

const buildCredenciadaLegacyFields = ({ codigo, credenciado, representante, cnpjCpf }) => {
  const digits = normalizeRequestValue(cnpjCpf).replace(/\D/g, '')
  const empresa = (normalizeCredenciadaText(credenciado, 100) || `CRED ${codigo}`).slice(0, 100)
  const condutor = (normalizeCredenciadaText(representante, 100) || empresa).slice(0, 100)
  const tipoPessoa = digits.length === 14 ? 'PJ' : 'PF'
  const placa = `CR${codigo}`.slice(0, 8)

  return {
    placa,
    empresa,
    condutor,
    tipoPessoa,
  }
}

const normalizeCredenciadaTipoPessoaValue = (value) => {
  const normalized = normalizeRequestValue(value).slice(0, 20)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()

  if (['COOPERATIVA', 'CO'].includes(normalized)) {
    return 'CO'
  }

  if (['PESSOA JURIDICA', 'JURIDICA', 'PJ'].includes(normalized)) {
    return 'PJ'
  }

  if (['PESSOA FISICA', 'FISICA', 'PF'].includes(normalized)) {
    return 'PF'
  }

  return ''
}

const normalizeVehicleCrm = (value) => {
  return normalizeRequestValue(value)
    .toUpperCase()
    .replace(/[^0-9A-Z.\-/]/g, '')
    .slice(0, 20)
}

const isVehicleCrmValid = (value) => {
  return /^[0-9A-Z.\-/]{1,20}$/.test(value)
}

const normalizeVehiclePlaca = (value) => {
  return normalizeRequestValue(value)
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '')
    .slice(0, 7)
}

const isVehiclePlacaValid = (value) => {
  return /^[A-Z]{3}-?\d{4}$/.test(value) || /^[A-Z]{3}-?\d[A-Z]\d{2}$/.test(value)
}

const getVeiculoPersistenceError = (error, fallbackMessage) => {
  if (error && typeof error === 'object') {
    const databaseError = error
    const constraintName = typeof databaseError.constraint === 'string' ? databaseError.constraint : ''
    const errorCode = typeof databaseError.code === 'string' ? databaseError.code : ''
    const errorMessage = error instanceof Error ? error.message : ''

    const isUniqueViolation = errorCode === '23505' || /viol[ao].+unicidade|duplicate key/i.test(errorMessage)

    if (constraintName === 'veiculo_crm_uk' || (isUniqueViolation && errorMessage.includes('veiculo_crm_uk'))) {
      return {
        status: 409,
        message: 'CRM j\u00e1 cadastrado',
      }
    }

    if (constraintName === 'veiculo_placa_uk' || (isUniqueViolation && errorMessage.includes('veiculo_placa_uk'))) {
      return {
        status: 409,
        message: 'Placa j\u00e1 cadastrada',
      }
    }

    if (constraintName === 'veiculo_crm_placa_uk' || (isUniqueViolation && errorMessage.includes('veiculo_crm_placa_uk'))) {
      return {
        status: 409,
        message: 'CRM e placa j\u00e1 cadastrado',
      }
    }
  }

  return {
    status: 500,
    message: error instanceof Error ? error.message : fallbackMessage,
  }
}

const buildVeiculoComparableSnapshot = (value) => {
  return {
    crm: normalizeVehicleCrm(value?.crm ?? ''),
    placas: normalizeVehiclePlaca(value?.placas ?? ''),
    ano: normalizeVehicleInteger(value?.ano ?? null, 4),
    capDetran: normalizeVehicleInteger(value?.capDetran ?? value?.cap_detran ?? null, 3),
    capTeg: normalizeVehicleInteger(value?.capTeg ?? value?.cap_teg ?? null, 3),
    capTegCreche: normalizeVehicleInteger(value?.capTegCreche ?? value?.cap_teg_creche ?? null, 3),
    capAcessivel: normalizeVehicleInteger(value?.capAcessivel ?? value?.cap_acessivel ?? null, 3),
    valCrm: normalizeRequestValue(value?.valCrm ?? value?.val_crm ?? ''),
    seguradora: normalizeCredenciadaText(value?.seguradora ?? '', 255),
    seguroInicio: normalizeRequestValue(value?.seguroInicio ?? value?.seguro_inicio ?? ''),
    seguroTermino: normalizeRequestValue(value?.seguroTermino ?? value?.seguro_termino ?? ''),
    tipoDeBancada: normalizeTipoDeBancada(value?.tipoDeBancada ?? value?.tipo_de_bancada ?? '') || '',
    tipoDeVeiculo: normalizeTipoDeVeiculo(value?.tipoDeVeiculo ?? value?.tipo_de_veiculo ?? '') || '',
    marcaModelo: normalizeCredenciadaText(value?.marcaModelo ?? value?.marca_modelo ?? '', 255),
    titular: normalizeCredenciadaText(value?.titular ?? '', 255),
    cnpjCpf: normalizeCnpjCpf(value?.cnpjCpf ?? value?.cnpj_cpf ?? ''),
    valorVeiculo: normalizeVehicleMoney(value?.valorVeiculo ?? value?.valor_veiculo ?? null),
    osEspecial: normalizeOsEspecial(value?.osEspecial ?? value?.os_especial ?? '') || '',
  }
}

const hasVeiculoSnapshotChanged = (currentItem, nextPayload) => {
  const currentSnapshot = buildVeiculoComparableSnapshot(currentItem)
  const nextSnapshot = buildVeiculoComparableSnapshot(nextPayload)

  return Object.keys(currentSnapshot).some((key) => currentSnapshot[key] !== nextSnapshot[key])
}

