const importCondutorXmlFile = async (fileName, { deleteMissing = false, progressFilePath = '' } = {}) => {
  const sanitizedFileName = path.basename(normalizeRequestValue(fileName))

  if (!sanitizedFileName) {
    throw new Error('Nome do arquivo XML e obrigatorio.')
  }

  if (path.extname(sanitizedFileName).toLowerCase() !== '.xml') {
    throw new Error('Informe um arquivo XML valido.')
  }

  const resolvedPath = path.resolve(importXmlDirectory, sanitizedFileName)

  if (!resolvedPath.startsWith(importXmlDirectory)) {
    throw new Error('Arquivo XML invalido.')
  }

  const xmlContent = await readFile(resolvedPath, 'utf8')
  const parsedRecords = parseCondutorXml(xmlContent)

  if (!parsedRecords.length) {
    throw new Error('Nenhum registro de condutor foi encontrado no XML informado.')
  }

  const normalizedRecords = []
  const skippedRecords = []

  for (const [index, record] of parsedRecords.entries()) {
    await appendXmlImportProgress(progressFilePath, 'Condutor', index + 1, parsedRecords.length, normalizeRequestValue(record.codigo))

    try {
      normalizedRecords.push(normalizeImportedCondutorRecord(record, index))
    } catch (error) {
      skippedRecords.push({
        index: index + 1,
        codigoXml: normalizeRequestValue(record.codigo),
        condutorXml: normalizeRequestValue(record.condutor),
        cpfCondutorXml: normalizeRequestValue(record.cpfCondutor),
        crmcXml: normalizeRequestValue(record.crmc),
        tipoVinculoXml: normalizeRequestValue(record.tipoVinculo),
        message: error instanceof Error ? error.message : `Registro ${index + 1}: erro ao validar o XML.`,
      })
    }
  }

  const client = await pool.connect()

  try {
    await client.query('BEGIN')
    await client.query('TRUNCATE TABLE condutor_import_recusa RESTART IDENTITY')
    let inserted = 0
    let updated = 0
    let deleted = 0
    const importedCodigoXmlSet = new Set(normalizedRecords.map((record) => String(record.codigo)).filter(Boolean))

    if (deleteMissing && importedCodigoXmlSet.size > 0) {
      const deleteResult = await client.query(
        `DELETE FROM condutor
          WHERE COALESCE(BTRIM(codigo_xml), '') <> ''
            AND NOT (BTRIM(codigo_xml) = ANY($1::text[]))`,
        [Array.from(importedCodigoXmlSet)],
      )
      deleted = deleteResult.rowCount ?? 0
    }

    for (const skippedRecord of skippedRecords) {
      await client.query(
        `INSERT INTO condutor_import_recusa (
           arquivo_xml,
           linha_xml,
           codigo_xml,
           condutor_xml,
           cpf_condutor_xml,
           crmc_xml,
           tipo_vinculo_xml,
           motivo_recusa,
           data_importacao
         )
         VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), NULLIF($7, ''), $8, NOW())`,
        [
          sanitizedFileName,
          skippedRecord.index,
          skippedRecord.codigoXml,
          skippedRecord.condutorXml,
          skippedRecord.cpfCondutorXml,
          skippedRecord.crmcXml,
          skippedRecord.tipoVinculoXml,
          skippedRecord.message,
        ],
      )
    }

    for (const record of normalizedRecords) {
      const existingByCodeResult = await client.query('SELECT codigo::text AS codigo FROM condutor WHERE codigo = $1 LIMIT 1', [record.codigo])
      const existingByCpfItem = await findCondutorByCpf(record.cpfCondutor, client)
      const existingByCodeCodigo = Number(existingByCodeResult.rows[0]?.codigo || 0)
      const existingByCpfCodigo = Number(existingByCpfItem?.codigo || 0)

      if (existingByCodeCodigo > 0 && existingByCpfCodigo > 0 && existingByCodeCodigo !== existingByCpfCodigo) {
        const skippedRecord = {
          index: record.index,
          codigoXml: String(record.codigo || ''),
          condutorXml: record.condutor,
          cpfCondutorXml: record.cpfCondutor,
          crmcXml: record.crmc,
          tipoVinculoXml: record.tipoVinculo,
          message: 'CPF do condutor ja vinculado a outro codigo cadastrado.',
        }

        skippedRecords.push(skippedRecord)
        await client.query(
          `INSERT INTO condutor_import_recusa (
             arquivo_xml,
             linha_xml,
             codigo_xml,
             condutor_xml,
             cpf_condutor_xml,
             crmc_xml,
             tipo_vinculo_xml,
             motivo_recusa,
             data_importacao
           )
           VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), NULLIF($7, ''), $8, NOW())`,
          [
            sanitizedFileName,
            skippedRecord.index,
            skippedRecord.codigoXml,
            skippedRecord.condutorXml,
            skippedRecord.cpfCondutorXml,
            skippedRecord.crmcXml,
            skippedRecord.tipoVinculoXml,
            skippedRecord.message,
          ],
        )
        continue
      }

      const targetCodigo = existingByCodeCodigo > 0 ? existingByCodeCodigo : existingByCpfCodigo

      if (targetCodigo > 0) {
        await client.query(
          `UPDATE condutor
           SET codigo_xml = $1,
               condutor = $2,
               cpf_condutor = $3,
               crmc = $4,
                validade_crmc = NULLIF($5, '')::date,
               validade_curso = NULLIF($6, '')::date,
               tipo_vinculo = NULLIF($7, ''),
               historico = NULLIF($8, ''),
               data_modificacao = NOW()
           WHERE codigo = $9`,
          [
            String(record.codigo),
            record.condutor,
            record.cpfCondutor,
            record.crmc,
            record.validadeCrmc,
            record.validadeCurso,
            record.tipoVinculo,
            record.historico,
            targetCodigo,
          ],
        )
        updated += 1
        continue
      }

      await client.query(
        `INSERT INTO condutor (
           codigo,
           codigo_xml,
           condutor,
           cpf_condutor,
           crmc,
           validade_crmc,
           validade_curso,
           tipo_vinculo,
           historico,
           data_inclusao,
           data_modificacao
         )
         VALUES ($1, $2, $3, $4, $5, NULLIF($6, '')::date, NULLIF($7, '')::date, NULLIF($8, ''), NULLIF($9, ''), NOW(), NOW())`,
        [
          record.codigo,
          String(record.codigo),
          record.condutor,
          record.cpfCondutor,
          record.crmc,
          record.validadeCrmc,
          record.validadeCurso,
          record.tipoVinculo,
          record.historico,
        ],
      )
      inserted += 1
    }

    if (normalizedRecords.length) {
      await client.query('SELECT setval(\'condutor_codigo_seq\', GREATEST(COALESCE((SELECT MAX(codigo) FROM condutor), 0), 1), true)')
    }
    await client.query('COMMIT')

    return {
      fileName: sanitizedFileName,
      filePath: resolvedPath,
      total: parsedRecords.length,
      processed: inserted + updated,
      inserted,
      updated,
      deleted,
      skipped: skippedRecords.length,
      skippedRecords: skippedRecords.slice(0, 20),
    }
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    client.release()
  }
}

const importMonitorXmlFile = async (fileName, { deleteMissing = false, progressFilePath = '' } = {}) => {
  const sanitizedFileName = path.basename(normalizeRequestValue(fileName))

  if (!sanitizedFileName) {
    throw new Error('Nome do arquivo XML e obrigatorio.')
  }

  if (path.extname(sanitizedFileName).toLowerCase() !== '.xml') {
    throw new Error('Informe um arquivo XML valido.')
  }

  const resolvedPath = path.resolve(importXmlDirectory, sanitizedFileName)

  if (!resolvedPath.startsWith(importXmlDirectory)) {
    throw new Error('Arquivo XML invalido.')
  }

  const xmlContent = await readFile(resolvedPath, 'utf8')
  const parsedRecords = parseMonitorXml(xmlContent)

  if (!parsedRecords.length) {
    throw new Error('Nenhum registro de monitor foi encontrado no XML informado.')
  }

  const normalizedRecords = []
  const skippedRecords = []

  for (const [index, record] of parsedRecords.entries()) {
    await appendXmlImportProgress(progressFilePath, 'Monitor', index + 1, parsedRecords.length, normalizeRequestValue(record.codigo))

    try {
      normalizedRecords.push(normalizeImportedMonitorRecord(record, index))
    } catch (error) {
      skippedRecords.push({
        index: index + 1,
        codigoXml: normalizeRequestValue(record.codigo),
        monitorXml: normalizeRequestValue(record.monitor),
        cpfMonitorXml: normalizeRequestValue(record.cpfMonitor),
        rgMonitorXml: normalizeRequestValue(record.rgMonitor),
        tipoVinculoXml: normalizeRequestValue(record.tipoVinculo),
        message: error instanceof Error ? error.message : `Registro ${index + 1}: erro ao validar o XML.`,
      })
    }
  }

  const client = await pool.connect()

  try {
    await client.query('BEGIN')
    await client.query('TRUNCATE TABLE monitor_import_recusa RESTART IDENTITY')
    let inserted = 0
    let updated = 0
    let deleted = 0
    const importedCodigoXmlSet = new Set(normalizedRecords.map((record) => String(record.codigo)).filter(Boolean))

    if (deleteMissing && importedCodigoXmlSet.size > 0) {
      const deleteResult = await client.query(
        `DELETE FROM monitor
          WHERE COALESCE(BTRIM(codigo_xml), '') <> ''
            AND NOT (BTRIM(codigo_xml) = ANY($1::text[]))`,
        [Array.from(importedCodigoXmlSet)],
      )
      deleted = deleteResult.rowCount ?? 0
    }

    const existingMonitorRowsResult = await client.query(
      `SELECT
         codigo::int AS codigo,
         regexp_replace(COALESCE(cpf_monitor, ''), '[^0-9]', '', 'g') AS cpf_digits
       FROM monitor`,
    )
    const existingMonitorCodeMap = new Map()
    const existingMonitorCpfMap = new Map()
    const pendingMonitorInsertMap = new Map()
    const pendingMonitorUpdateMap = new Map()

    for (const row of existingMonitorRowsResult.rows) {
      const codigo = Number(row.codigo)

      if (codigo > 0) {
        existingMonitorCodeMap.set(codigo, codigo)
      }

      const cpfDigits = normalizeRequestValue(row.cpf_digits)

      if (codigo > 0 && cpfDigits && !existingMonitorCpfMap.has(cpfDigits)) {
        existingMonitorCpfMap.set(cpfDigits, codigo)
      }
    }

    for (const skippedRecord of skippedRecords) {
      await client.query(
        `INSERT INTO monitor_import_recusa (
           arquivo_xml,
           linha_xml,
           codigo_xml,
           monitor_xml,
           cpf_monitor_xml,
           rg_monitor_xml,
           tipo_vinculo_xml,
           motivo_recusa,
           data_importacao
         )
         VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), NULLIF($7, ''), $8, NOW())`,
        [
          sanitizedFileName,
          skippedRecord.index,
          skippedRecord.codigoXml,
          skippedRecord.monitorXml,
          skippedRecord.cpfMonitorXml,
          skippedRecord.rgMonitorXml,
          skippedRecord.tipoVinculoXml,
          skippedRecord.message,
        ],
      )
    }

    for (const record of normalizedRecords) {
      const existingByCodeCodigo = Number(existingMonitorCodeMap.get(record.codigo) || 0)
      const cpfDigits = extractDocumentDigits(record.cpfMonitor)
      const existingByCpfCodigo = Number((cpfDigits && existingMonitorCpfMap.get(cpfDigits)) || 0)

      if (existingByCodeCodigo > 0 && existingByCpfCodigo > 0 && existingByCodeCodigo !== existingByCpfCodigo) {
        const skippedRecord = {
          index: record.index,
          codigoXml: String(record.codigo || ''),
          monitorXml: record.monitor,
          cpfMonitorXml: record.cpfMonitor,
          rgMonitorXml: record.rgMonitor,
          tipoVinculoXml: record.tipoVinculo,
          message: 'CPF do monitor ja vinculado a outro codigo cadastrado.',
        }

        skippedRecords.push(skippedRecord)
        await client.query(
          `INSERT INTO monitor_import_recusa (
             arquivo_xml,
             linha_xml,
             codigo_xml,
             monitor_xml,
             cpf_monitor_xml,
             rg_monitor_xml,
             tipo_vinculo_xml,
             motivo_recusa,
             data_importacao
           )
           VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), NULLIF($7, ''), $8, NOW())`,
          [
            sanitizedFileName,
            skippedRecord.index,
            skippedRecord.codigoXml,
            skippedRecord.monitorXml,
            skippedRecord.cpfMonitorXml,
            skippedRecord.rgMonitorXml,
            skippedRecord.tipoVinculoXml,
            skippedRecord.message,
          ],
        )
        continue
      }

      const targetCodigo = existingByCodeCodigo > 0 ? existingByCodeCodigo : existingByCpfCodigo

      if (targetCodigo > 0) {
        const nextRecord = {
          codigo: targetCodigo,
          codigo_xml: String(record.codigo),
          monitor: record.monitor,
          cpf_monitor: record.cpfMonitor,
          curso_monitor: record.cursoMonitor,
          validade_curso: record.validadeCurso,
          tipo_vinculo: record.tipoVinculo,
          nascimento: record.nascimento,
        }

        if (pendingMonitorInsertMap.has(targetCodigo)) {
          pendingMonitorInsertMap.set(targetCodigo, nextRecord)
        } else {
          pendingMonitorUpdateMap.set(targetCodigo, nextRecord)
        }
        updated += 1
        if (cpfDigits) {
          existingMonitorCpfMap.set(cpfDigits, targetCodigo)
        }
        existingMonitorCodeMap.set(targetCodigo, targetCodigo)
        continue
      }

      pendingMonitorInsertMap.set(record.codigo, {
        codigo: record.codigo,
        codigo_xml: String(record.codigo),
        monitor: record.monitor,
        cpf_monitor: record.cpfMonitor,
        curso_monitor: record.cursoMonitor,
        validade_curso: record.validadeCurso,
        tipo_vinculo: record.tipoVinculo,
        nascimento: record.nascimento,
      })
      existingMonitorCodeMap.set(record.codigo, record.codigo)
      if (cpfDigits) {
        existingMonitorCpfMap.set(cpfDigits, record.codigo)
      }
      inserted += 1
    }

    const pendingMonitorUpdateRecords = Array.from(pendingMonitorUpdateMap.values())

    if (pendingMonitorUpdateRecords.length) {
      await client.query(
        `WITH import_records AS (
           SELECT *
           FROM jsonb_to_recordset($1::jsonb) AS record(
             codigo int,
             codigo_xml text,
             monitor text,
             cpf_monitor text,
             curso_monitor text,
             validade_curso text,
             tipo_vinculo text,
             nascimento text
           )
         )
         UPDATE monitor AS target
          SET codigo_xml = NULLIF(import_records.codigo_xml, ''),
            monitor = import_records.monitor,
                rg_monitor = NULL,
                cpf_monitor = import_records.cpf_monitor,
                curso_monitor = NULLIF(import_records.curso_monitor, '')::date,
                validade_curso = NULLIF(import_records.validade_curso, '')::date,
                tipo_vinculo = NULLIF(import_records.tipo_vinculo, ''),
                nascimento = NULLIF(import_records.nascimento, '')::date,
                data_modificacao = NOW()
           FROM import_records
          WHERE target.codigo = import_records.codigo`,
        [JSON.stringify(pendingMonitorUpdateRecords)],
      )
    }

    const pendingMonitorInsertRecords = Array.from(pendingMonitorInsertMap.values())

    if (pendingMonitorInsertRecords.length) {
      await client.query(
        `INSERT INTO monitor (
           codigo,
            codigo_xml,
           monitor,
           cpf_monitor,
           curso_monitor,
           validade_curso,
           tipo_vinculo,
           nascimento,
           data_inclusao,
           data_modificacao
         )
         SELECT
           record.codigo,
           NULLIF(record.codigo_xml, ''),
           record.monitor,
           record.cpf_monitor,
           NULLIF(record.curso_monitor, '')::date,
           NULLIF(record.validade_curso, '')::date,
           NULLIF(record.tipo_vinculo, ''),
           NULLIF(record.nascimento, '')::date,
           NOW(),
           NOW()
         FROM jsonb_to_recordset($1::jsonb) AS record(
           codigo int,
           codigo_xml text,
           monitor text,
           cpf_monitor text,
           curso_monitor text,
           validade_curso text,
           tipo_vinculo text,
           nascimento text
         )`,
        [JSON.stringify(pendingMonitorInsertRecords)],
      )
    }

    if (normalizedRecords.length) {
      await client.query('SELECT setval(\'monitor_codigo_seq\', GREATEST(COALESCE((SELECT MAX(codigo) FROM monitor), 0), 1), true)')
    }
    await client.query('COMMIT')

    return {
      fileName: sanitizedFileName,
      filePath: resolvedPath,
      total: parsedRecords.length,
      processed: normalizedRecords.length,
      inserted,
      updated,
      deleted,
      skipped: skippedRecords.length,
      skippedRecords: skippedRecords.slice(0, 20),
    }
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    client.release()
  }
}

const parseCepsXml = (xmlContent) => {
  const parsed = xmlParser.parse(xmlContent)
  const rawRecords = parsed?.dataroot?.Cep
  const records = (Array.isArray(rawRecords)
    ? rawRecords
    : rawRecords
      ? [rawRecords]
      : [])
    .filter((record) => record && typeof record === 'object')

  return records.map((record) => ({
    cep: normalizeRequestValue(record?.CEP),
    logradouro: normalizeRequestValue(record?.Logradouro),
    complemento: normalizeRequestValue(record?.Complemento),
    bairro: normalizeRequestValue(record?.Bairro),
    municipio: normalizeRequestValue(record?.Municipio),
    uf: normalizeRequestValue(record?.UF),
    ibge: normalizeRequestValue(record?.IBGE),
  }))
}

const normalizeImportedCepRecord = (record, index) => {
  const cep = normalizeCep(record.cep)
  const logradouro = normalizeCepImportLogradouro(record.logradouro, 255)
  const complemento = normalizeCredenciadaText(record.complemento, 255)
  const bairro = normalizeCredenciadaText(record.bairro, 120)
  const municipio = normalizeCredenciadaText(record.municipio, 120)
  const uf = normalizeRequestValue(record.uf).toUpperCase().replace(/[^A-Z]/g, '').slice(0, 2)
  const ibge = normalizeRequestValue(record.ibge).replace(/\D/g, '').slice(0, 10)
  const itemLabel = `Registro ${index + 1}`

  if (!cep || !isCepValid(cep)) {
    throw new Error(`${itemLabel}: CEP invalido no XML.`)
  }

  if (!municipio) {
    throw new Error(`${itemLabel}: municipio obrigatorio no XML.`)
  }

  if (!uf || uf.length !== 2) {
    throw new Error(`${itemLabel}: UF invalida no XML.`)
  }

  return { cep, logradouro, complemento, bairro, municipio, uf, ibge }
}

const importCepsXmlFile = async (fileName) => {
  const sanitizedFileName = path.basename(normalizeRequestValue(fileName))

  if (!sanitizedFileName) {
    throw new Error('Nome do arquivo XML e obrigatorio.')
  }

  if (path.extname(sanitizedFileName).toLowerCase() !== '.xml') {
    throw new Error('Informe um arquivo XML valido.')
  }

  const resolvedPath = path.resolve(importXmlDirectory, sanitizedFileName)

  if (!resolvedPath.startsWith(importXmlDirectory)) {
    throw new Error('Arquivo XML invalido.')
  }

  const xmlContent = await readFile(resolvedPath, 'utf8')
  const parsedRecords = parseCepsXml(xmlContent)

  if (!parsedRecords.length) {
    throw new Error('Nenhum registro de CEP foi encontrado no XML informado.')
  }

  const normalizedRecords = []
  const skippedRecords = []

  parsedRecords.forEach((record, index) => {
    try {
      normalizedRecords.push(normalizeImportedCepRecord(record, index))
    } catch (error) {
      skippedRecords.push({
        index: index + 1,
        cepXml: normalizeRequestValue(record.cep),
        logradouroXml: normalizeRequestValue(record.logradouro),
        municipioXml: normalizeRequestValue(record.municipio),
        ufXml: normalizeRequestValue(record.uf),
        message: error instanceof Error ? error.message : `Registro ${index + 1}: erro ao validar o XML.`,
      })
    }
  })

  const client = await pool.connect()

  try {
    await client.query('BEGIN')
    await client.query(`TRUNCATE TABLE ${cepImportRecusaTableName} RESTART IDENTITY`)
    let inserted = 0
    let updated = 0

    for (const skippedRecord of skippedRecords) {
      await client.query(
        `INSERT INTO ${cepImportRecusaTableName} (
           arquivo_xml,
           linha_xml,
           cep_xml,
           logradouro_xml,
           municipio_xml,
           uf_xml,
           motivo_recusa,
           data_importacao
         )
         VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), $7, NOW())`,
        [
          sanitizedFileName,
          skippedRecord.index,
          skippedRecord.cepXml,
          skippedRecord.logradouroXml,
          skippedRecord.municipioXml,
          skippedRecord.ufXml,
          skippedRecord.message,
        ],
      )
    }

    for (const record of normalizedRecords) {
      const existingResult = await client.query(
        `SELECT 1 FROM ${cepTableName} WHERE BTRIM(cep) = $1 LIMIT 1`,
        [record.cep],
      )

      if (existingResult.rowCount > 0) {
        await client.query(
          `UPDATE ${cepTableName}
           SET logradouro = NULLIF($1, ''),
               complemento = NULLIF($2, ''),
               bairro = NULLIF($3, ''),
               municipio = $4,
               uf = $5,
               ibge = NULLIF($6, ''),
               data_modificacao = NOW()
           WHERE BTRIM(cep) = $7`,
          [record.logradouro, record.complemento, record.bairro, record.municipio, record.uf, record.ibge, record.cep],
        )
        updated += 1
        continue
      }

      await client.query(
        `INSERT INTO ${cepTableName} (
           cep,
           logradouro,
           complemento,
           bairro,
           municipio,
           uf,
           ibge,
           data_inclusao,
           data_modificacao
         )
         VALUES ($1, NULLIF($2, ''), NULLIF($3, ''), NULLIF($4, ''), $5, $6, NULLIF($7, ''), NOW(), NOW())`,
        [record.cep, record.logradouro, record.complemento, record.bairro, record.municipio, record.uf, record.ibge],
      )
      inserted += 1
    }

    await client.query('COMMIT')

    return {
      fileName: sanitizedFileName,
      filePath: resolvedPath,
      total: parsedRecords.length,
      processed: normalizedRecords.length,
      inserted,
      updated,
      skipped: skippedRecords.length,
      skippedRecords: skippedRecords.slice(0, 20),
    }
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    client.release()
  }
}

const importVeiculoXmlFile = async (fileName, { actor = 'IMPORTACAO_XML', deleteMissing = false, progressFilePath = '' } = {}) => {
  const sanitizedFileName = path.basename(normalizeRequestValue(fileName))

  if (!sanitizedFileName) {
    throw new Error('Nome do arquivo XML e obrigatorio.')
  }

  if (path.extname(sanitizedFileName).toLowerCase() !== '.xml') {
    throw new Error('Informe um arquivo XML valido.')
  }

  const resolvedPath = path.resolve(importXmlDirectory, sanitizedFileName)

  if (!resolvedPath.startsWith(importXmlDirectory)) {
    throw new Error('Arquivo XML invalido.')
  }

  const xmlContent = await readFile(resolvedPath, 'utf8')
  const parsedRecords = parseVeiculoXml(xmlContent)

  await resetXmlImportProgress(progressFilePath)

  if (!parsedRecords.length) {
    throw new Error('Nenhum registro de veiculo foi encontrado no XML informado.')
  }

  const normalizedRecords = []
  const skippedRecords = []
  const ignoredImportMessageSuffixes = new Set([
    ': tipo de bancada invalido no XML.',
  ])

  for (const [index, record] of parsedRecords.entries()) {
    await appendXmlImportProgress(progressFilePath, 'Veiculo', index + 1, parsedRecords.length, normalizeRequestValue(record.crm || record.codigo))

    try {
      normalizedRecords.push(normalizeImportedVeiculoRecord(record, index))
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : `Registro ${index + 1}: erro ao validar o XML.`

      if ([...ignoredImportMessageSuffixes].some((suffix) => errorMessage.endsWith(suffix))) {
        continue
      }

      skippedRecords.push({
        index: index + 1,
        codigoXml: normalizeRequestValue(record.codigo),
        crmXml: normalizeRequestValue(record.crm),
        placasXml: normalizeRequestValue(record.placas),
        tipoDeVeiculoXml: normalizeRequestValue(record.tipoDeVeiculo),
        message: errorMessage,
      })
    }
  }

  const client = await pool.connect()

  try {
    await client.query('BEGIN')
    await client.query('TRUNCATE TABLE veiculo_import_recusa RESTART IDENTITY')
    const recalculateVehicleCodigos = new Set()
    let inserted = 0
    let updated = 0
    let deleted = 0
    const importedCodigoXmlSet = new Set(normalizedRecords.map((record) => String(record.codigo)).filter(Boolean))

    if (deleteMissing && importedCodigoXmlSet.size > 0) {
      const deletedItemsResult = await client.query(
        `SELECT ${veiculoAuditSelectClause}
           FROM veiculo
          WHERE COALESCE(BTRIM(codigo_xml), '') <> ''
            AND NOT (BTRIM(codigo_xml) = ANY($1::text[]))`,
        [Array.from(importedCodigoXmlSet)],
      )

      for (const deletedItem of deletedItemsResult.rows) {
        await insertVeiculoHistoricoEntry(client, deletedItem, {
          acao: 'IMPORTACAO_XML_EXCLUSAO',
          realizadoPor: actor,
        })
      }

      const deleteResult = await client.query(
        `DELETE FROM veiculo
          WHERE COALESCE(BTRIM(codigo_xml), '') <> ''
            AND NOT (BTRIM(codigo_xml) = ANY($1::text[]))`,
        [Array.from(importedCodigoXmlSet)],
      )
      deleted = deleteResult.rowCount ?? 0
    }

    for (const skippedRecord of skippedRecords) {
      await client.query(
        `INSERT INTO veiculo_import_recusa (
           arquivo_xml,
           linha_xml,
           codigo_xml,
           crm_xml,
           placas_xml,
           tipo_de_veiculo_xml,
           motivo_recusa,
           data_importacao
         )
         VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), NULLIF($6, ''), $7, NOW())`,
        [
          sanitizedFileName,
          skippedRecord.index,
          skippedRecord.codigoXml,
          skippedRecord.crmXml,
          skippedRecord.placasXml,
          skippedRecord.tipoDeVeiculoXml,
          skippedRecord.message,
        ],
      )
    }

    for (const record of normalizedRecords) {
      const existingItemByCodigo = await fetchVeiculoAuditItemByCodigo(client, record.codigo)
      const existingItemByPlaca = await fetchVeiculoAuditItemByPlaca(client, record.placas)
      const existingItemByCrm = await fetchVeiculoAuditItemByCrm(client, record.crm)
      let existingItem = existingItemByCodigo ?? existingItemByPlaca ?? existingItemByCrm

      if (
        existingItemByCodigo
        && existingItemByPlaca
        && Number(existingItemByCodigo.codigo) !== Number(existingItemByPlaca.codigo)
      ) {
        existingItem = existingItemByPlaca
      } else if (
        existingItemByCodigo
        && existingItemByCrm
        && Number(existingItemByCodigo.codigo) !== Number(existingItemByCrm.codigo)
      ) {
        existingItem = existingItemByCrm
      }

      if (existingItem) {
        let targetRecord = record
        const targetCodigo = Number(existingItem.codigo)
        const conflictingCodeOwner = record.codigo === targetCodigo
          ? null
          : await fetchVeiculoAuditItemByCodigo(client, record.codigo)

        if (conflictingCodeOwner && Number(conflictingCodeOwner.codigo) !== targetCodigo) {
          targetRecord = {
            ...record,
            codigo: targetCodigo,
          }
        }

        if (hasVeiculoSnapshotChanged(existingItem, targetRecord)) {
          await insertVeiculoHistoricoEntry(client, existingItem, {
            acao: 'IMPORTACAO_XML',
            realizadoPor: actor,
          })
        }

        await upsertImportedVeiculoByCodigo(client, targetCodigo, targetRecord)
        recalculateVehicleCodigos.add(targetCodigo)
        updated += 1
        continue
      }

      await client.query(
        `INSERT INTO veiculo (
           codigo,
           codigo_xml,
           crm,
           placas,
           ano,
           cap_detran,
           cap_teg,
           cap_teg_creche,
           cap_acessivel,
           val_crm,
           seguradora,
           seguro_inicio,
           seguro_termino,
           tipo_de_bancada,
           tipo_de_veiculo,
           marca_modelo,
           titular,
           cnpj_cpf,
           valor_veiculo,
           os_especial,
           data_inclusao,
           data_modificacao
         )
         VALUES ($1, NULLIF($2, ''), NULLIF($3, ''), NULLIF($4, ''), $5, $6, $7, $8, $9, NULLIF($10, '')::date, NULLIF($11, ''), NULLIF($12, '')::date, NULLIF($13, '')::date, NULLIF($14, ''), NULLIF($15, ''), NULLIF($16, ''), NULLIF($17, ''), NULLIF($18, ''), $19, NULLIF($20, ''), NOW(), NOW())`,
        [
          record.codigo,
          String(record.codigo),
          record.crm,
          record.placas,
          record.ano,
          record.capDetran,
          record.capTeg,
          record.capTegCreche,
          record.capAcessivel,
          record.valCrm,
          record.seguradora,
          record.seguroInicio,
          record.seguroTermino,
          record.tipoDeBancada,
          record.tipoDeVeiculo,
          record.marcaModelo,
          record.titular,
          record.cnpjCpf,
          record.valorVeiculo,
          record.osEspecial,
        ],
      )
      recalculateVehicleCodigos.add(record.codigo)
      inserted += 1
    }

    if (recalculateVehicleCodigos.size > 0) {
      const recalculatedVehicles = await recalculateSpecialVehicleValues(client, {
        codigos: [...recalculateVehicleCodigos],
      })

      await syncCredenciamentoTermoValoresByRecalculatedVehicles(
        recalculatedVehicles,
        client,
        normalizedRecords.map((record) => record.crm),
      )
    } else if (normalizedRecords.length) {
      await syncCredenciamentoTermoValoresByVehicleCrms(
        normalizedRecords.map((record) => record.crm),
        client,
      )
    }

    if (normalizedRecords.length) {
      await client.query('SELECT setval(\'veiculo_codigo_seq\', GREATEST(COALESCE((SELECT MAX(codigo) FROM veiculo), 0), 1), true)')
    }
    await client.query('COMMIT')

    return {
      fileName: sanitizedFileName,
      filePath: resolvedPath,
      total: parsedRecords.length,
      processed: normalizedRecords.length,
      inserted,
      updated,
      deleted,
      skipped: skippedRecords.length,
      skippedRecords: skippedRecords.slice(0, 20),
    }
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    client.release()
  }
}

const importCredenciamentoTermoXmlFile = async (fileName, { realizadoPor = 'IMPORTACAO_XML', deleteMissing = true, progressFilePath = '' } = {}) => {
  const sanitizedFileName = path.basename(normalizeRequestValue(fileName))

  if (!sanitizedFileName) {
    throw new Error('Nome do arquivo XML e obrigatorio.')
  }

  if (path.extname(sanitizedFileName).toLowerCase() !== '.xml') {
    throw new Error('Informe um arquivo XML valido.')
  }

  const resolvedPath = path.resolve(importXmlDirectory, sanitizedFileName)

  if (!resolvedPath.startsWith(importXmlDirectory)) {
    throw new Error('Arquivo XML invalido.')
  }

  const xmlContent = await readFile(resolvedPath, 'utf8')
  const parsedRecords = parseCredenciamentoTermoXml(xmlContent)

  if (!parsedRecords.length) {
    throw new Error('Nenhum registro de credenciamento termo foi encontrado no XML informado.')
  }

  const normalizedRecords = []
  const skippedRecords = []

  for (const [index, record] of parsedRecords.entries()) {
    await appendXmlImportProgress(progressFilePath, 'Credenciamento Termo', index + 1, parsedRecords.length, normalizeRequestValue(record['C�digo']))

    try {
      normalizedRecords.push(...buildImportedCredenciamentoTermoRecords(record, index))
    } catch (error) {
      skippedRecords.push({
        index: index + 1,
        codigoXml: normalizeRequestValue(record['C�digo']),
        credenciadoXml: normalizeRequestValue(record.Credenciado),
        aditivoXml: '',
        message: error instanceof Error ? error.message : `Registro ${index + 1}: erro ao validar o XML.`,
      })
    }
  }

  const client = await pool.connect()

  try {
    await client.query('BEGIN')
    await client.query(`TRUNCATE TABLE ${credenciamentoTermoImportRecusaTableName} RESTART IDENTITY`)
    let inserted = 0
    let updated = 0
    let deleted = 0
    const allowedAditivosByCodigoXml = new Map()

    for (const record of normalizedRecords) {
      const currentAditivos = allowedAditivosByCodigoXml.get(record.codigoXml) ?? new Set()
      currentAditivos.add(record.aditivo)
      allowedAditivosByCodigoXml.set(record.codigoXml, currentAditivos)
    }

    if (deleteMissing) {
      for (const [codigoXml, aditivos] of allowedAditivosByCodigoXml.entries()) {
        const deletedItems = await listCredenciamentoTermoItemsByCodigoXmlExceptAditivos(client, codigoXml, Array.from(aditivos))
        await insertTermoHistoricoEntries(client, deletedItems, {
          acao: 'IMPORTACAO_XML_EXCLUSAO',
          realizadoPor,
        })

        const deleteResult = await client.query(
          `DELETE FROM ${credenciamentoTermoTableName}
           WHERE codigo_xml = $1
             AND NOT (aditivo = ANY($2::integer[]))`,
          [codigoXml, Array.from(aditivos)],
        )
        deleted += deleteResult.rowCount ?? 0
      }
    }

    for (const skippedRecord of skippedRecords) {
      await client.query(
        `INSERT INTO ${credenciamentoTermoImportRecusaTableName} (
           arquivo_xml,
           linha_xml,
           codigo_xml,
           credenciado_xml,
           aditivo_xml,
           motivo_recusa,
           data_importacao
         )
         VALUES ($1, $2, NULLIF($3, ''), NULLIF($4, ''), NULLIF($5, ''), $6, NOW())`,
        [
          sanitizedFileName,
          skippedRecord.index,
          skippedRecord.codigoXml,
          skippedRecord.credenciadoXml,
          skippedRecord.aditivoXml,
          skippedRecord.message,
        ],
      )
    }

    for (const record of normalizedRecords) {
      let credenciadaItem = await findCredenciadaByCnpjCpf(record.cnpjCpf, client)

      if (!credenciadaItem && !record.cnpjCpf) {
        credenciadaItem = await findCredenciadaByName(record.credenciado, client)
      }

      if (!credenciadaItem) {
        await client.query(
          `INSERT INTO ${credenciamentoTermoImportRecusaTableName} (
             arquivo_xml,
             linha_xml,
             codigo_xml,
             credenciado_xml,
             aditivo_xml,
             motivo_recusa,
             data_importacao
           )
           VALUES ($1, $2, $3, $4, $5, $6, NOW())`,
          [
            sanitizedFileName,
            record.codigoXml,
            String(record.codigoXml),
            record.credenciado,
            String(record.aditivo),
            record.cnpjCpf
              ? 'Credenciado nao encontrado na tabela credenciada pelo CNPJ/CPF informado no XML.'
              : 'Credenciado nao encontrado na tabela credenciada pelo nome informado no XML.',
          ],
        )
        continue
      }

      await syncCredenciadaTpOptante(credenciadaItem.codigo, record.tpOptante, client)

      const existingResult = await findExistingCredenciamentoTermoImportItem(client, record)

      const values = [
        record.codigoXml,
        Number(credenciadaItem.codigo),
        record.termoAdesao,
        record.sei,
        record.aditivo,
        record.situacaoPublicacao,
        record.situacaoEmissao,
        record.inicioVigencia,
        record.terminoVigencia,
        record.compDataAditivo,
        record.statusAditivo,
        record.dataPubAditivo,
        record.checkAditivo,
        record.statusTermo,
        record.tipoTermo,
        record.especificacaoSei,
        record.valorContrato,
        record.objeto,
        record.dataPublicacao,
        record.infoSei,
        record.valorContratoAtualizado,
        record.vencimentoGeral,
        record.mesRenovacao,
      ]

      if (existingResult?.codigo) {
        const existingItem = await fetchCredenciamentoTermoItemByCodigo(client, existingResult.codigo)
        await insertTermoHistoricoEntry(client, existingItem, {
          acao: 'IMPORTACAO_XML_ALTERACAO',
          realizadoPor,
        })

        await client.query(
          `UPDATE ${credenciamentoTermoTableName}
           SET codigo_xml = $1,
               credenciada_codigo = $2,
               termo_adesao = $3,
               sei = NULLIF($4, ''),
               aditivo = $5,
               situacao_publicacao = NULLIF($6, ''),
               situacao_emissao = NULLIF($7, ''),
               inicio_vigencia = NULLIF($8, '')::date,
               termino_vigencia = NULLIF($9, '')::date,
               comp_data_aditivo = NULLIF($10, '')::date,
               status_aditivo = NULLIF($11, ''),
               data_pub_aditivo = NULLIF($12, '')::date,
               check_aditivo = $13,
               status_termo = NULLIF($14, ''),
               tipo_termo = NULLIF($15, ''),
               especificacao_sei = NULLIF($16, ''),
               valor_contrato = $17,
                objeto = NULLIF($18, ''),
               data_publicacao = NULLIF($19, '')::date,
               info_sei = NULLIF($20, ''),
               valor_contrato_atualizado = $21,
               vencimento_geral = NULLIF($22, '')::date,
               mes_renovacao = NULLIF($23, ''),
               data_modificacao = NOW()
              WHERE codigo = $24`,
          [...values, existingResult.codigo],
        )
        updated += 1
        continue
      }

      await client.query(
        `INSERT INTO ${credenciamentoTermoTableName} (
           codigo_xml,
           credenciada_codigo,
           termo_adesao,
           sei,
           aditivo,
           situacao_publicacao,
           situacao_emissao,
           inicio_vigencia,
           termino_vigencia,
           comp_data_aditivo,
           status_aditivo,
           data_pub_aditivo,
           check_aditivo,
           status_termo,
           tipo_termo,
           especificacao_sei,
           valor_contrato,
           objeto,
           data_publicacao,
           info_sei,
           valor_contrato_atualizado,
           vencimento_geral,
           mes_renovacao,
           data_inclusao,
           data_modificacao
         )
         VALUES ($1, $2, $3, NULLIF($4, ''), $5, NULLIF($6, ''), NULLIF($7, ''), NULLIF($8, '')::date, NULLIF($9, '')::date, NULLIF($10, '')::date, NULLIF($11, ''), NULLIF($12, '')::date, $13, NULLIF($14, ''), NULLIF($15, ''), NULLIF($16, ''), $17, NULLIF($18, ''), NULLIF($19, '')::date, NULLIF($20, ''), $21, NULLIF($22, '')::date, NULLIF($23, ''), NOW(), NOW())`,
        values,
      )
      inserted += 1
    }

    if (normalizedRecords.length) {
      await client.query(`SELECT setval('${credenciamentoTermoCodigoSequenceName}', GREATEST(COALESCE((SELECT MAX(codigo) FROM ${credenciamentoTermoTableName}), 0), 1), true)`)
    }

    await client.query('COMMIT')

    return {
      fileName: sanitizedFileName,
      filePath: resolvedPath,
      total: parsedRecords.length,
      processed: normalizedRecords.length,
      inserted,
      updated,
      deleted,
      skipped: skippedRecords.length,
      skippedRecords: skippedRecords.slice(0, 20),
    }
  } catch (error) {
    await client.query('ROLLBACK')
    throw error
  } finally {
    client.release()
  }
}

const findExistingCredenciamentoTermoImportItem = async (executor, record) => {
  const normalizedTermoAdesao = normalizeOrdemServicoTermoAdesao(record.termoAdesao)

  if (normalizedTermoAdesao) {
    const existingByTermoResult = await executor.query(
      `SELECT codigo
         FROM ${credenciamentoTermoTableName}
        WHERE aditivo = $1
          AND ${credenciamentoTermoNormalizedTermoExpression} = REGEXP_REPLACE($2, '\\D', '', 'g')
        ORDER BY codigo ASC
        LIMIT 1`,
      [record.aditivo, normalizedTermoAdesao],
    )

    if (existingByTermoResult.rowCount > 0) {
      return existingByTermoResult.rows[0]
    }
  }

  const existingByCodigoXmlResult = await executor.query(
    `SELECT codigo
       FROM ${credenciamentoTermoTableName}
      WHERE codigo_xml = $1
        AND aditivo = $2
      LIMIT 1`,
    [record.codigoXml, record.aditivo],
  )

  return existingByCodigoXmlResult.rows[0] ?? null
}

const fetchCredenciamentoTermoItemByCodigo = async (executor, codigo) => {
  const normalizedCodigo = normalizeCondutorCodigo(codigo)

  if (!Number.isInteger(normalizedCodigo) || normalizedCodigo <= 0) {
    return null
  }

  const result = await executor.query(
    `SELECT
       ${credenciamentoTermoSelectClause}
     FROM ${credenciamentoTermoTableName}
     WHERE codigo = $1
     LIMIT 1`,
    [normalizedCodigo],
  )

  const item = result.rows[0] ?? null

  if (!item) {
    return null
  }

  return {
    ...item,
    valorContratoExtenso: buildCurrencyExtenso(item.valor_contrato),
  }
}

const listCredenciamentoTermoItemsByNormalizedTermoAdesao = async (executor, termoAdesao) => {
  const normalizedTermo = normalizeOrdemServicoTermoAdesao(termoAdesao)

  if (!normalizedTermo) {
    return []
  }

  const result = await executor.query(
    `SELECT
       ${credenciamentoTermoSelectClause}
     FROM ${credenciamentoTermoTableName}
     WHERE ${credenciamentoTermoNormalizedTermoExpression} = REGEXP_REPLACE($1, '\\D', '', 'g')
     ORDER BY aditivo ASC, codigo ASC`,
    [normalizedTermo],
  )

  return result.rows
}

const listCredenciamentoTermoItemsByCodigoXmlExceptAditivos = async (executor, codigoXml, allowedAditivos = []) => {
  const normalizedCodigoXml = Number.parseInt(String(codigoXml ?? ''), 10)
  const normalizedAditivos = Array.from(new Set((Array.isArray(allowedAditivos) ? allowedAditivos : [allowedAditivos])
    .map((aditivo) => Number.parseInt(String(aditivo ?? ''), 10))
    .filter((aditivo) => Number.isInteger(aditivo))))

  if (!Number.isInteger(normalizedCodigoXml) || normalizedCodigoXml <= 0) {
    return []
  }

  const result = await executor.query(
    `SELECT
       ${credenciamentoTermoSelectClause}
     FROM ${credenciamentoTermoTableName}
     WHERE codigo_xml = $1
       AND NOT (aditivo = ANY($2::integer[]))
     ORDER BY aditivo ASC, codigo ASC`,
    [normalizedCodigoXml, normalizedAditivos],
  )

  return result.rows
}

