        filePath: processedFiles === 1 ? (lastMovedFilePath || resolvedImportFiles.filePaths[0]) : '',
        fileName: processedFiles === 1 ? path.basename(lastMovedFilePath || resolvedImportFiles.filePaths[0]) : '',
